{
  "name": "FinanceFlow AI - Controle de Gastos",
  "description": "Uma aplicação avançada de gestão financeira pessoal com insights inteligentes via Gemini AI, gráficos interativos e rastreamento de despesas em tempo real."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type ExpenseType = 'Fixa' | 'Variável';
export type ExpenseStatus = 'Pago' | 'Pendente';

export interface Expense {
  id: string;
  description: string;
  category: string;
  type: ExpenseType;
  expectedValue: number;
  paidValue: number;
  dueDate: string;
  status: ExpenseStatus;
}

export interface CategoryInfo {
  name: string;
  color: string;
  icon: string;
}

export interface SummaryData {
  totalExpected: number;
  totalPaid: number;
  balance: number;
  progress: number;
  fixedTotal: number;
  variableTotal: number;
}

import { GoogleGenAI } from "@google/genai";
import { Expense } from "../types";

export const getFinancialInsights = async (expenses: Expense[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const summary = expenses.map(e => ({
    desc: e.description,
    cat: e.category,
    val: e.expectedValue,
    paid: e.paidValue,
    status: e.status
  }));

  const prompt = `
    Como um analista financeiro sênior, analise estas despesas mensais e forneça 3 insights curtos e acionáveis em português do Brasil.
    Foque em:
    1. Onde é possível economizar.
    2. Alerta de vencimentos ou desequilíbrio entre tipos de gastos.
    3. Elogio por bons hábitos financeiros se houver.

    Responda apenas com os 3 pontos em formato de lista Markdown.

    Dados: ${JSON.stringify(summary)}
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Não foi possível gerar insights no momento. Verifique sua conexão ou tente novamente mais tarde.";
  }
};

import React, { useState, useMemo, useEffect } from 'react';
import { 
  TrendingUp, 
  TrendingDown, 
  Wallet, 
  Activity, 
  BrainCircuit, 
  Plus, 
  RefreshCw,
  LayoutDashboard,
  Receipt,
  PieChart as PieChartIcon
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell,
  PieChart,
  Pie
} from 'recharts';
import { INITIAL_EXPENSES, CATEGORIES } from './constants';
import { Expense, SummaryData } from './types';
import { getFinancialInsights } from './services/geminiService';

const App: React.FC = () => {
  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('finance_expenses');
    return saved ? JSON.parse(saved) : INITIAL_EXPENSES;
  });
  const [insights, setInsights] = useState<string>("");
  const [loadingInsights, setLoadingInsights] = useState(false);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'list'>('dashboard');

  useEffect(() => {
    localStorage.setItem('finance_expenses', JSON.stringify(expenses));
  }, [expenses]);

  const summary = useMemo((): SummaryData => {
    const totalExpected = expenses.reduce((acc, curr) => acc + curr.expectedValue, 0);
    const totalPaid = expenses.reduce((acc, curr) => acc + curr.paidValue, 0);
    const fixedTotal = expenses.filter(e => e.type === 'Fixa').reduce((acc, curr) => acc + curr.paidValue, 0);
    const variableTotal = expenses.filter(e => e.type === 'Variável').reduce((acc, curr) => acc + curr.paidValue, 0);

    return {
      totalExpected,
      totalPaid,
      balance: totalExpected - totalPaid,
      progress: totalExpected > 0 ? (totalPaid / totalExpected) * 100 : 0,
      fixedTotal,
      variableTotal
    };
  }, [expenses]);

  const chartData = useMemo(() => {
    const cats = Array.from(new Set(expenses.map(e => e.category)));
    return cats.map(cat => ({
      name: cat,
      value: expenses.filter(e => e.category === cat).reduce((acc, curr) => acc + curr.paidValue, 0),
      color: CATEGORIES[cat]?.color || '#ccc'
    })).sort((a, b) => b.value - a.value);
  }, [expenses]);

  const pieData = useMemo(() => [
    { name: 'Fixas', value: summary.fixedTotal, color: '#22d3ee' },
    { name: 'Variáveis', value: summary.variableTotal, color: '#f472b6' }
  ], [summary]);

  const handleUpdateExpense = (id: string, field: keyof Expense, value: any) => {
    setExpenses(prev => prev.map(e => e.id === id ? { ...e, [field]: value } : e));
  };

  const toggleStatus = (id: string) => {
    setExpenses(prev => prev.map(e => {
      if (e.id === id) {
        const newStatus = e.status === 'Pago' ? 'Pendente' : 'Pago';
        const newPaidValue = newStatus === 'Pago' ? e.expectedValue : 0;
        return { ...e, status: newStatus, paidValue: newPaidValue };
      }
      return e;
    }));
