            title="Total Pago" 
            value={formatBRL(summary.totalPaid)} 
            icon={<TrendingDown className="w-5 h-5 text-emerald-400" />}
            color="emerald"
          />
          <Card 
            title="Saldo Restante" 
            value={formatBRL(summary.balance)} 
            icon={<Wallet className="w-5 h-5 text-amber-400" />}
            color="amber"
          />
          <div className="bg-slate-900 p-5 rounded-2xl border border-slate-800 flex flex-col justify-between">
            <div className="flex items-center justify-between mb-2">
              <span className="text-sm text-slate-400">Progresso</span>
              <Activity className="w-5 h-5 text-purple-400" />
            </div>
            <div className="flex flex-col gap-2">
              <span className="text-2xl font-bold mono">{Math.round(summary.progress)}%</span>
              <div className="h-2 bg-slate-800 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-gradient-to-r from-purple-500 to-pink-500 transition-all duration-1000" 
                  style={{ width: `${summary.progress}%` }}
                />
              </div>
            </div>
          </div>
        </section>

        {activeTab === 'dashboard' ? (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            {/* Insights Panel */}
            <div className="lg:col-span-3">
              {insights && (
                <div className="bg-indigo-500/10 border border-indigo-500/20 rounded-2xl p-6 mb-8 animate-in fade-in slide-in-from-top-4">
                  <div className="flex items-center gap-3 mb-4">
                    <BrainCircuit className="w-6 h-6 text-indigo-400" />
                    <h3 className="font-bold text-lg text-indigo-300">Insights Estratégicos (Gemini AI)</h3>
                  </div>
                  <div className="prose prose-invert max-w-none text-slate-300 leading-relaxed">
                    {insights.split('\n').map((line, i) => (
