                      </td>
                      <td className="px-6 py-4">
                        <span className={`text-[10px] uppercase font-bold px-2 py-0.5 rounded ${expense.type === 'Fixa' ? 'bg-cyan-500/10 text-cyan-400 border border-cyan-500/20' : 'bg-pink-500/10 text-pink-400 border border-pink-500/20'}`}>
                          {expense.type}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <input 
                          type="number" 
                          value={expense.expectedValue}
                          onChange={(e) => handleUpdateExpense(expense.id, 'expectedValue', parseFloat(e.target.value) || 0)}
                          className="w-24 bg-transparent text-right mono text-sm outline-none focus:bg-slate-800 rounded px-2"
                        />
                      </td>
                      <td className="px-6 py-4 text-right">
                        <input 
                          type="number" 
                          value={expense.paidValue}
                          onChange={(e) => handleUpdateExpense(expense.id, 'paidValue', parseFloat(e.target.value) || 0)}
                          className="w-24 bg-transparent text-right mono text-sm outline-none focus:bg-slate-800 rounded px-2"
                        />
                      </td>
                      <td className="px-6 py-4 text-center">
                        <span className="mono text-sm text-slate-400">{expense.dueDate || '-'}</span>
                      </td>
                      <td className="px-6 py-4 text-center">
                        <button 
                          onClick={() => toggleStatus(expense.id)}
                          className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-semibold transition-all ${expense.status === 'Pago' ? 'bg-emerald-500/20 text-emerald-400 hover:bg-emerald-500/30' : 'bg-amber-500/20 text-amber-400 hover:bg-amber-500/30'}`}
                        >
                          <div className={`w-1.5 h-1.5 rounded-full ${expense.status === 'Pago' ? 'bg-emerald-500' : 'bg-amber-500'}`} />
                          {expense.status}
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

interface CardProps {
  title: string;
  value: string;
  icon: React.ReactNode;
  color: 'blue' | 'emerald' | 'amber';
}

const Card: React.FC<CardProps> = ({ title, value, icon, color }) => {
  const colorMap = {
    blue: 'bg-blue-500/10 border-blue-500/20',
    emerald: 'bg-emerald-500/10 border-emerald-500/20',
    amber: 'bg-amber-500/10 border-amber-500/20'
  };

  return (
    <div className={`p-5 rounded-2xl border bg-slate-900 shadow-sm flex flex-col justify-between transition-transform hover:scale-[1.02] cursor-default`}>
      <div className="flex items-center justify-between mb-4">
        <span className="text-sm text-slate-400 font-medium">{title}</span>
        <div className={`p-2 rounded-xl bg-slate-800`}>
          {icon}
        </div>
      </div>
      <p className="text-2xl font-bold mono tracking-tight">{value}</p>
    </div>
  );
};

export default App;

