                <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                  <span className="text-xs text-slate-400">Total Pago</span>
                  <span className="text-lg font-bold mono text-white">{formatBRL(summary.totalPaid)}</span>
                </div>
              </div>
              <div className="flex justify-center gap-8 mt-4">
                {pieData.map((item) => (
                  <div key={item.name} className="flex items-center gap-2">
                    <div className="w-3 h-3 rounded-full" style={{ backgroundColor: item.color }} />
                    <div className="flex flex-col">
                      <span className="text-xs text-slate-400">{item.name}</span>
                      <span className="text-sm font-semibold text-white">{formatBRL(item.value)}</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        ) : (
          /* Expense List View */
          <div className="bg-slate-900 rounded-2xl border border-slate-800 overflow-hidden shadow-2xl">
            <div className="p-6 border-b border-slate-800 flex justify-between items-center bg-slate-900/50 backdrop-blur-md">
              <h3 className="font-bold text-lg text-white">Listagem de Gastos</h3>
              <button className="flex items-center gap-2 px-3 py-1.5 bg-emerald-500/10 text-emerald-400 hover:bg-emerald-500/20 rounded-lg text-sm transition-colors border border-emerald-500/20 font-medium">
                <Plus className="w-4 h-4" /> Adicionar
              </button>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-950/50 text-slate-400 text-xs uppercase tracking-wider">
                  <tr>
                    <th className="px-6 py-4 font-semibold">Descrição</th>
                    <th className="px-6 py-4 font-semibold">Categoria</th>
                    <th className="px-6 py-4 font-semibold">Tipo</th>
                    <th className="px-6 py-4 font-semibold text-right">Previsto</th>
                    <th className="px-6 py-4 font-semibold text-right">Pago</th>
                    <th className="px-6 py-4 font-semibold text-center">Venc.</th>
                    <th className="px-6 py-4 font-semibold text-center">Status</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-800">
                  {expenses.map((expense) => (
                    <tr key={expense.id} className="hover:bg-slate-800/40 transition-colors group">
                      <td className="px-6 py-4">
                        <span className="font-medium text-slate-100">{expense.description}</span>
                      </td>
                      <td className="px-6 py-4">
                        <span 
                          className="inline-flex items-center px-2.5 py-1 rounded-full text-xs font-semibold"
                          style={{ backgroundColor: `${CATEGORIES[expense.category]?.color}25`, color: CATEGORIES[expense.category]?.color }}
                        >
                          {expense.category}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <span className={`text-[10px] uppercase font-bold px-2 py-0.5 rounded ${expense.type === 'Fixa' ? 'bg-cyan-500/10 text-cyan-400 border border-cyan-500/20' : 'bg-pink-500/10 text-pink-400 border border-pink-500/20'}`}>
                          {expense.type}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <input 
                          type="number" 
                          value={expense.expectedValue}
                          onChange={(e) => handleUpdateExpense(expense.id, 'expectedValue', parseFloat(e.target.value) || 0)}
                          className="w-24 bg-transparent text-right mono text-sm outline-none focus:bg-slate-800 rounded px-2 text-white border-b border-transparent focus:border-slate-700 transition-all"
                        />
                      </td>
                      <td className="px-6 py-4 text-right">
                        <input 
                          type="number" 
                          value={expense.paidValue}
                          onChange={(e) => handleUpdateExpense(expense.id, 'paidValue', parseFloat(e.target.value) || 0)}
                          className="w-24 bg-transparent text-right mono text-sm outline-none focus:bg-slate-800 rounded px-2 text-white border-b border-transparent focus:border-slate-700 transition-all"
                        />
                      </td>
                      <td className="px-6 py-4 text-center">
                        <span className="mono text-sm text-slate-300">{expense.dueDate || '-'}</span>
                      </td>
                      <td className="px-6 py-4 text-center">
                        <button 
                          onClick={() => toggleStatus(expense.id)}
                          className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-bold transition-all shadow-sm ${expense.status === 'Pago' ? 'bg-emerald-500/20 text-emerald-400 hover:bg-emerald-500/30 ring-1 ring-emerald-500/30' : 'bg-amber-500/20 text-amber-400 hover:bg-amber-500/30 ring-1 ring-amber-500/30'}`}
                        >
                          <div className={`w-1.5 h-1.5 rounded-full ${expense.status === 'Pago' ? 'bg-emerald-400' : 'bg-amber-400'}`} />
                          {expense.status}
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

interface CardProps {
  title: string;
  value: string;
  icon: React.ReactNode;
  color: 'blue' | 'emerald' | 'amber';
}

const Card: React.FC<CardProps> = ({ title, value, icon, color }) => {
  return (
    <div className={`p-5 rounded-2xl border bg-slate-900 border-slate-800 shadow-sm flex flex-col justify-between transition-transform hover:scale-[1.02] cursor-default group`}>
      <div className="flex items-center justify-between mb-4">
        <span className="text-sm text-slate-400 font-semibold group-hover:text-slate-300 transition-colors">{title}</span>
        <div className={`p-2 rounded-xl bg-slate-800 group-hover:bg-slate-700 transition-colors`}>
          {icon}
        </div>
      </div>
      <p className="text-2xl font-bold mono tracking-tight text-white">{value}</p>
    </div>
  );
};

export default App;

export type ExpenseType = 'Fixa' | 'Variável';
export type ExpenseStatus = 'Pago' | 'Pendente';

export interface Expense {
  id: string;
  description: string;
  category: string;
  type: ExpenseType;
  expectedValue: number;
  paidValue: number;
  dueDate: string;
  status: ExpenseStatus;
}

export interface CategoryInfo {
  name: string;
  color: string;
  icon: string;
}

export interface SummaryData {
  totalExpected: number;
  totalPaid: number;
  balance: number;
  progress: number;
  fixedTotal: number;
  variableTotal: number;
}

export type MonthlyDataStore = Record<number, Expense[]>;

import React, { useState, useMemo, useEffect } from 'react';
import { 
  TrendingUp, 
  TrendingDown, 
  Wallet, 
  Activity, 
  BrainCircuit, 
  Plus, 
  RefreshCw,
  LayoutDashboard,
  Receipt,
  PieChart as PieChartIcon,
  Calendar,
  History,
  ChevronLeft,
  ChevronRight,
  ArrowUpRight,
  ArrowDownRight,
  CheckCircle2,
  Trash2
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell,
  PieChart,
  Pie,
  AreaChart,
  Area
} from 'recharts';
import { INITIAL_EXPENSES, CATEGORIES } from './constants';
import { Expense, SummaryData, MonthlyDataStore } from './types';
import { getFinancialInsights } from './services/geminiService';

const MONTHS = [
  'Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho',
  'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'
];

const App: React.FC = () => {
  const [selectedMonth, setSelectedMonth] = useState<number>(new Date().getMonth());
  const [monthlyStore, setMonthlyStore] = useState<MonthlyDataStore>(() => {
    const savedStore = localStorage.getItem('finance_monthly_store');
    if (savedStore) return JSON.parse(savedStore);

    // Tenta migrar dados da versão antiga (janeiro) se existirem
    const oldData = localStorage.getItem('finance_expenses');
    const initialStore: MonthlyDataStore = {};

    MONTHS.forEach((_, index) => {
      if (index === 0 && oldData) {
        // Se for Janeiro e existirem dados antigos, usa eles
        initialStore[index] = JSON.parse(oldData);
      } else {
        // Senão, usa o template inicial
        initialStore[index] = INITIAL_EXPENSES.map(e => ({ 
          ...e, 
          id: `${e.id}-${index}-${Math.random().toString(36).substr(2, 9)}` 
        }));
      }
    });
    return initialStore;
  });

  const [insights, setInsights] = useState<string>("");
  const [loadingInsights, setLoadingInsights] = useState(false);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'list' | 'history'>('dashboard');

  useEffect(() => {
    localStorage.setItem('finance_monthly_store', JSON.stringify(monthlyStore));
  }, [monthlyStore]);

  const expenses = useMemo(() => monthlyStore[selectedMonth] || [], [monthlyStore, selectedMonth]);

  const getMonthSummary = (monthIdx: number): SummaryData => {
    const monthExpenses = monthlyStore[monthIdx] || [];
    const totalExpected = monthExpenses.reduce((acc, curr) => acc + curr.expectedValue, 0);
    const totalPaid = monthExpenses.reduce((acc, curr) => acc + curr.paidValue, 0);
    const fixedTotal = monthExpenses.filter(e => e.type === 'Fixa').reduce((acc, curr) => acc + curr.paidValue, 0);
    const variableTotal = monthExpenses.filter(e => e.type === 'Variável').reduce((acc, curr) => acc + curr.paidValue, 0);

    return {
      totalExpected,
      totalPaid,
      balance: totalExpected - totalPaid,
      progress: totalExpected > 0 ? (totalPaid / totalExpected) * 100 : 0,
      fixedTotal,
      variableTotal
    };
  };

  const currentSummary = useMemo(() => getMonthSummary(selectedMonth), [expenses]);
  const prevSummary = useMemo(() => selectedMonth > 0 ? getMonthSummary(selectedMonth - 1) : null, [monthlyStore, selectedMonth]);

  const historyData = useMemo(() => {
    return MONTHS.map((name, index) => {
      const s = getMonthSummary(index);
      return {
        name: name.substring(0, 3),
        fullName: name,
        pago: s.totalPaid,
        previsto: s.totalExpected,
        economia: s.totalExpected - s.totalPaid > 0 ? s.totalExpected - s.totalPaid : 0,
        index
      };
    });
  }, [monthlyStore]);

  const chartData = useMemo(() => {
    const cats = Array.from(new Set(expenses.map(e => e.category)));
    return cats.map((cat: string) => ({
      name: cat,
      value: expenses.filter(e => e.category === cat).reduce((acc, curr) => acc + curr.paidValue, 0),
      color: CATEGORIES[cat]?.color || '#ccc'
    })).sort((a, b) => b.value - a.value);
  }, [expenses]);

  const handleUpdateExpense = (id: string, field: keyof Expense, value: any) => {
    setMonthlyStore(prev => {
      const newExpenses = prev[selectedMonth].map(e => e.id === id ? { ...e, [field]: value } : e);
      return { ...prev, [selectedMonth]: newExpenses };
    });
  };

  const removeExpense = (id: string) => {
    setMonthlyStore(prev => ({
      ...prev,
      [selectedMonth]: prev[selectedMonth].filter(e => e.id !== id)
    }));
  };

  const toggleStatus = (id: string) => {
    setMonthlyStore(prev => {
      const newExpenses = prev[selectedMonth].map(e => {
        if (e.id === id) {
          const newStatus = e.status === 'Pago' ? 'Pendente' : 'Pago';
          const newPaidValue = newStatus === 'Pago' ? e.expectedValue : 0;
          return { ...e, status: newStatus, paidValue: newPaidValue };
        }
        return e;
      });
      return { ...prev, [selectedMonth]: newExpenses };
    });
  };

  const fetchInsights = async () => {
    setLoadingInsights(true);
    const text = await getFinancialInsights(expenses);
    setInsights(text || "Sem insights disponíveis.");
    setLoadingInsights(false);
  };

  const formatBRL = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const getComparison = (curr: number, prev: number | undefined) => {
    if (prev === undefined || prev === null || prev === 0) return null;
    const diff = ((curr - prev) / prev) * 100;
    return {
      value: Math.abs(diff).toFixed(1),
      isIncrease: diff > 0
    };
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 flex flex-col md:flex-row">
      {/* Sidebar */}
      <aside className="w-full md:w-72 bg-slate-900 border-b md:border-b-0 md:border-r border-slate-800 flex flex-col sticky top-0 h-auto md:h-screen z-20">
        <div className="p-6">
          <div className="flex items-center gap-3 mb-8">
            <div className="p-2 bg-emerald-500 rounded-lg">
              <Wallet className="w-6 h-6 text-slate-950" />
            </div>
            <h1 className="text-xl font-bold bg-gradient-to-r from-emerald-400 to-cyan-400 bg-clip-text text-transparent">FinanceFlow</h1>
          </div>

          <nav className="flex flex-col gap-2 mb-8">
            <button 
              onClick={() => setActiveTab('dashboard')}
              className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'dashboard' ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20' : 'text-slate-400 hover:bg-slate-800'}`}
            >
              <LayoutDashboard className="w-5 h-5" />
              <span className="font-medium">Dashboard</span>
            </button>
            <button 
              onClick={() => setActiveTab('list')}
              className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'list' ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20' : 'text-slate-400 hover:bg-slate-800'}`}
            >
              <Receipt className="w-5 h-5" />
              <span className="font-medium">Detalhamento</span>
            </button>
            <button 
              onClick={() => setActiveTab('history')}
              className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'history' ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20' : 'text-slate-400 hover:bg-slate-800'}`}
            >
              <History className="w-5 h-5" />
              <span className="font-medium">Histórico Anual</span>
            </button>
          </nav>

          <div className="space-y-4">
            <p className="text-[10px] font-bold uppercase tracking-widest text-slate-500 px-4">Calendário {new Date().getFullYear()}</p>
            <div className="grid grid-cols-3 gap-2">
              {MONTHS.map((month, idx) => (
                <button
                  key={month}
                  onClick={() => setSelectedMonth(idx)}
                  className={`py-2 text-[10px] font-bold rounded-lg border transition-all ${selectedMonth === idx ? 'bg-emerald-500 border-emerald-500 text-slate-950' : 'bg-slate-800/50 border-slate-700 text-slate-400 hover:border-slate-500'}`}
                >
                  {month.substring(0, 3)}
                </button>
              ))}
            </div>
          </div>
        </div>

        <div className="mt-auto p-6 border-t border-slate-800">
          <div className="p-4 bg-slate-800/50 rounded-2xl border border-slate-700/50">
            <div className="flex items-center justify-between mb-1">
              <p className="text-xs text-slate-400">Selecionado</p>
              <CheckCircle2 className="w-3 h-3 text-emerald-400" />
            </div>
            <p className="text-sm font-bold text-white uppercase">{MONTHS[selectedMonth]}</p>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-4 md:p-8 overflow-y-auto">
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
          <div>
            <div className="flex items-center gap-2 text-emerald-400 text-xs font-bold uppercase tracking-wider mb-1">
              <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
              Gestão Financeira • {MONTHS[selectedMonth]}
            </div>
            <h2 className="text-2xl font-bold text-white">
              {activeTab === 'dashboard' ? 'Visão Geral' : activeTab === 'list' ? 'Lista de Despesas' : 'Análise Histórica'}
            </h2>
          </div>

          <div className="flex items-center gap-3">
             <div className="flex bg-slate-900 rounded-xl p-1 border border-slate-800">
                <button 
                  onClick={() => setSelectedMonth(prev => Math.max(0, prev - 1))}
                  className="p-2 hover:bg-slate-800 rounded-lg text-slate-400 transition-colors"
                >
                  <ChevronLeft className="w-5 h-5" />
                </button>
                <div className="px-4 py-2 text-sm font-bold text-slate-200 min-w-[100px] text-center uppercase tracking-wide">
                  {MONTHS[selectedMonth].substring(0, 3)}
                </div>
                <button 
                  onClick={() => setSelectedMonth(prev => Math.min(11, prev + 1))}
                  className="p-2 hover:bg-slate-800 rounded-lg text-slate-400 transition-colors"
                >
                  <ChevronRight className="w-5 h-5" />
                </button>
             </div>

             {activeTab !== 'history' && (
               <button 
                onClick={fetchInsights}
                disabled={loadingInsights}
                className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 disabled:bg-indigo-900 rounded-xl font-bold transition-all shadow-lg shadow-indigo-500/20 text-white text-sm"
              >
                <BrainCircuit className={`w-4 h-4 ${loadingInsights ? 'animate-spin' : ''}`} />
                Insights IA
              </button>
             )}
          </div>
        </header>

        {activeTab === 'history' ? (
          /* History View */
          <div className="space-y-8 animate-in fade-in duration-500">
            <section className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <Card 
                title="Total Pago no Ano" 
                value={formatBRL(historyData.reduce((acc, curr) => acc + curr.pago, 0))} 
                icon={<ArrowUpRight className="w-5 h-5 text-emerald-400" />}
              />
              <Card 
                title="Média Mensal" 
                value={formatBRL(historyData.reduce((acc, curr) => acc + curr.pago, 0) / 12)} 
                icon={<Activity className="w-5 h-5 text-indigo-400" />}
              />
              <Card 
                title="Economia Total" 
                value={formatBRL(historyData.reduce((acc, curr) => acc + curr.economia, 0))} 
                icon={<TrendingUp className="w-5 h-5 text-emerald-400" />}
              />
            </section>

            <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800">
              <h3 className="text-lg font-bold text-white mb-8 flex items-center gap-2">
                <Activity className="w-5 h-5 text-indigo-400" />
                Evolução de Gastos vs Economia
              </h3>
              <div className="h-[400px]">
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={historyData}>
                    <defs>
                      <linearGradient id="colorPago" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#6366f1" stopOpacity={0.3}/>
                        <stop offset="95%" stopColor="#6366f1" stopOpacity={0}/>
                      </linearGradient>
                      <linearGradient id="colorEconomia" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#10b981" stopOpacity={0.3}/>
                        <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" vertical={false} />
                    <XAxis dataKey="name" stroke="#64748b" fontSize={12} tickLine={false} axisLine={false} dy={10} />
                    <YAxis stroke="#64748b" fontSize={12} tickLine={false} axisLine={false} tickFormatter={(v) => `R$${v}`} />
                    <Tooltip 
                      contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #1e293b', borderRadius: '16px' }}
                      itemStyle={{ fontWeight: 'bold' }}
                      formatter={(v: number) => formatBRL(v)}
                    />
                    <Area type="monotone" dataKey="pago" stroke="#6366f1" strokeWidth={3} fillOpacity={1} fill="url(#colorPago)" />
                    <Area type="monotone" dataKey="economia" stroke="#10b981" strokeWidth={3} fillOpacity={1} fill="url(#colorEconomia)" />
                  </AreaChart>
                </ResponsiveContainer>
              </div>
            </div>

            <div className="bg-slate-900 rounded-3xl border border-slate-800 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-950/50 text-slate-500 text-[10px] uppercase font-bold tracking-widest">
                  <tr>
                    <th className="px-6 py-5">Mês</th>
                    <th className="px-6 py-5 text-right">Previsto</th>
                    <th className="px-6 py-5 text-right">Realizado</th>
                    <th className="px-6 py-5 text-right">Resultado</th>
                    <th className="px-6 py-5 text-center">Ação</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-800/50">
                  {historyData.map((m) => (
                    <tr key={m.index} className="hover:bg-slate-800/30 transition-colors">
                      <td className="px-6 py-4 font-bold text-white">{m.fullName}</td>
                      <td className="px-6 py-4 text-right mono text-slate-300">{formatBRL(m.previsto)}</td>
                      <td className="px-6 py-4 text-right mono text-white">{formatBRL(m.pago)}</td>
                      <td className="px-6 py-4 text-right">
                        <span className={`mono font-bold ${m.economia > 0 ? 'text-emerald-400' : 'text-slate-400'}`}>
                          {m.economia > 0 ? `+ ${formatBRL(m.economia)}` : 'R$ 0,00'}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-center">
                        <button 
                          onClick={() => { setSelectedMonth(m.index); setActiveTab('dashboard'); }}
                          className="text-xs font-bold text-indigo-400 hover:text-indigo-300 underline"
                        >
                          Ver Mês
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        ) : activeTab === 'dashboard' ? (
          /* Dashboard View */
          <>
            <section className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
              <Card 
                title="Total Previsto" 
                value={formatBRL(currentSummary.totalExpected)} 
                icon={<TrendingUp className="w-5 h-5 text-blue-400" />}
                comparison={getComparison(currentSummary.totalExpected, prevSummary?.totalExpected)}
              />
              <Card 
                title="Total Pago" 
                value={formatBRL(currentSummary.totalPaid)} 
                icon={<TrendingDown className="w-5 h-5 text-emerald-400" />}
                comparison={getComparison(currentSummary.totalPaid, prevSummary?.totalPaid)}
              />
              <Card 
                title="Saldo em Aberto" 
                value={formatBRL(currentSummary.balance)} 
                icon={<Wallet className="w-5 h-5 text-amber-400" />}
              />
              <div className="bg-slate-900 p-5 rounded-3xl border border-slate-800 flex flex-col justify-between">
                <div className="flex items-center justify-between mb-2">
                  <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Meta Mensal</span>
                  <Activity className="w-5 h-5 text-purple-400" />
                </div>
                <div className="flex flex-col gap-2">
                  <span className="text-2xl font-bold mono text-white">{Math.round(currentSummary.progress)}%</span>
                  <div className="h-2 bg-slate-800 rounded-full overflow-hidden">
                    <div className="h-full bg-gradient-to-r from-emerald-500 to-indigo-500 transition-all duration-1000" style={{ width: `${currentSummary.progress}%` }} />
                  </div>
                </div>
              </div>
            </section>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-3">
                {insights && (
                  <div className="bg-indigo-500/10 border border-indigo-500/20 rounded-3xl p-6 mb-8 animate-in slide-in-from-top-4">
                    <div className="flex items-center gap-3 mb-4">
                      <BrainCircuit className="w-6 h-6 text-indigo-400" />
                      <h3 className="font-bold text-lg text-indigo-300">Inteligência {MONTHS[selectedMonth]}</h3>
                    </div>
                    <div className="prose prose-invert max-w-none text-slate-200 leading-relaxed font-medium">
                      {insights.split('\n').map((line, i) => (
                        <p key={i} className="mb-2">{line}</p>
                      ))}
                    </div>
                  </div>
                )}
              </div>

              <div className="lg:col-span-2 bg-slate-900 p-8 rounded-3xl border border-slate-800">
                <h3 className="font-bold text-lg text-white mb-8 flex items-center gap-2">
                  <PieChartIcon className="w-5 h-5 text-cyan-400" />
                  Investimento por Categoria
                </h3>
                <div className="h-[300px]">
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={chartData} layout="vertical">
                      <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" horizontal={false} />
                      <XAxis type="number" hide />
                      <YAxis dataKey="name" type="category" stroke="#94a3b8" fontSize={12} width={100} tickLine={false} axisLine={false} />
                      <Tooltip cursor={{fill: '#1e293b'}} contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #1e293b', borderRadius: '12px' }} formatter={(value: number) => formatBRL(value)} />
                      <Bar dataKey="value" radius={[0, 8, 8, 0]} barSize={32}>
                        {chartData.map((entry, index) => <Cell key={`cell-${index}`} fill={entry.color} />)}
                      </Bar>
                    </BarChart>
                  </ResponsiveContainer>
                </div>
              </div>

              <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800 flex flex-col items-center">
                <h3 className="font-bold text-lg text-white mb-8 w-full flex items-center gap-2">
                  <RefreshCw className="w-5 h-5 text-pink-400" />
                  Divisão da Natureza
                </h3>
                <div className="h-[250px] w-full relative">
                  <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                      <Pie
                        data={[
                          { name: 'Fixas', value: currentSummary.fixedTotal },
                          { name: 'Variáveis', value: currentSummary.variableTotal }
                        ]}
                        cx="50%" cy="50%" innerRadius={70} outerRadius={90} paddingAngle={8} dataKey="value" stroke="none"
                      >
                        <Cell fill="#22d3ee" />
                        <Cell fill="#f472b6" />
                      </Pie>
                      <Tooltip contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #1e293b', borderRadius: '12px' }} formatter={(value: number) => formatBRL(value)} />
                    </PieChart>
                  </ResponsiveContainer>
                  <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                    <span className="text-[10px] uppercase font-bold text-slate-500 tracking-widest">Realizado</span>
                    <span className="text-xl font-bold text-white mono">{formatBRL(currentSummary.totalPaid)}</span>
                  </div>
                </div>
                <div className="flex flex-col gap-3 w-full mt-6">
                  <div className="flex justify-between items-center p-3 rounded-2xl bg-slate-800/40 border border-slate-700/50">
                    <div className="flex items-center gap-2">
                      <div className="w-3 h-3 rounded-full bg-cyan-400" />
                      <span className="text-xs text-slate-300 font-bold uppercase tracking-wide">Despesas Fixas</span>
                    </div>
                    <span className="text-sm font-bold text-white mono">{formatBRL(currentSummary.fixedTotal)}</span>
                  </div>
                  <div className="flex justify-between items-center p-3 rounded-2xl bg-slate-800/40 border border-slate-700/50">
                    <div className="flex items-center gap-2">
                      <div className="w-3 h-3 rounded-full bg-pink-400" />
                      <span className="text-xs text-slate-300 font-bold uppercase tracking-wide">Variáveis</span>
                    </div>
                    <span className="text-sm font-bold text-white mono">{formatBRL(currentSummary.variableTotal)}</span>
                  </div>
                </div>
              </div>
            </div>
          </>
        ) : (
          /* Expense List View */
          <div className="bg-slate-900 rounded-3xl border border-slate-800 overflow-hidden shadow-2xl animate-in fade-in zoom-in-95 duration-300">
            <div className="p-6 border-b border-slate-800 flex justify-between items-center bg-slate-900/50 backdrop-blur-md">
              <h3 className="font-bold text-lg text-white flex items-center gap-2">
                <Receipt className="w-5 h-5 text-emerald-400" />
                Registros de {MONTHS[selectedMonth]}
              </h3>
              <button 
                onClick={() => {
                  const newExp: Expense = {
                    id: Date.now().toString(),
                    description: 'Nova Despesa',
                    category: 'Utilidades',
                    type: 'Variável',
                    expectedValue: 0,
                    paidValue: 0,
                    dueDate: '',
                    status: 'Pendente'
                  };
                  setMonthlyStore(prev => ({ ...prev, [selectedMonth]: [...prev[selectedMonth], newExp] }));
                }}
                className="flex items-center gap-2 px-4 py-2 bg-emerald-500/10 text-emerald-400 hover:bg-emerald-500/20 rounded-xl text-sm transition-all border border-emerald-500/20 font-bold"
              >
                <Plus className="w-4 h-4" /> Adicionar Gasto
              </button>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-950/50 text-slate-400 text-[10px] uppercase font-bold tracking-widest">
                  <tr>
                    <th className="px-6 py-5">Descrição</th>
                    <th className="px-6 py-5">Categoria</th>
                    <th className="px-6 py-5">Tipo</th>
                    <th className="px-6 py-5 text-right">Valor Previsto</th>
                    <th className="px-6 py-5 text-right">Valor Pago</th>
                    <th className="px-6 py-5 text-center">Dia</th>
                    <th className="px-6 py-5 text-center">Status</th>
                    <th className="px-2 py-5 text-center"></th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-800/50">
                  {expenses.map((expense) => (
                    <tr key={expense.id} className="hover:bg-slate-800/30 transition-colors group">
                      <td className="px-6 py-4">
                        <input 
                          type="text" 
                          value={expense.description}
                          onChange={(e) => handleUpdateExpense(expense.id, 'description', e.target.value)}
                          className="bg-transparent text-white font-bold outline-none focus:bg-slate-800 rounded px-2 py-1 w-full"
                        />
                      </td>
                      <td className="px-6 py-4">
                        <select 
                          value={expense.category}
                          onChange={(e) => handleUpdateExpense(expense.id, 'category', e.target.value)}
                          className="bg-transparent text-xs font-bold outline-none cursor-pointer rounded px-2 py-1"
                          style={{ color: CATEGORIES[expense.category]?.color }}
                        >
                          {Object.keys(CATEGORIES).map(cat => <option key={cat} value={cat} className="bg-slate-900 text-white">{cat}</option>)}
                        </select>
                      </td>
                      <td className="px-6 py-4">
                        <span className={`text-[10px] uppercase font-bold px-2 py-0.5 rounded ${expense.type === 'Fixa' ? 'bg-cyan-500/10 text-cyan-400 border border-cyan-500/20' : 'bg-pink-500/10 text-pink-400 border border-pink-500/20'}`}>
                          {expense.type}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <input 
                          type="number" 
                          value={expense.expectedValue}
                          onChange={(e) => handleUpdateExpense(expense.id, 'expectedValue', parseFloat(e.target.value) || 0)}
                          className="w-24 bg-transparent text-right mono text-sm outline-none focus:bg-slate-800 rounded px-2 text-white font-bold"
                        />
                      </td>
                      <td className="px-6 py-4 text-right">
                        <input 
                          type="number" 
                          value={expense.paidValue}
                          onChange={(e) => handleUpdateExpense(expense.id, 'paidValue', parseFloat(e.target.value) || 0)}
                          className="w-24 bg-transparent text-right mono text-sm outline-none focus:bg-slate-800 rounded px-2 text-white font-bold"
                        />
                      </td>
                      <td className="px-6 py-4 text-center">
                        <input 
                          type="text" 
                          value={expense.dueDate}
                          maxLength={2}
                          placeholder="--"
                          onChange={(e) => handleUpdateExpense(expense.id, 'dueDate', e.target.value)}
                          className="w-8 bg-transparent text-center mono text-sm text-slate-300 outline-none focus:bg-slate-800 rounded"
                        />
                      </td>
                      <td className="px-6 py-4 text-center">
                        <button 
                          onClick={() => toggleStatus(expense.id)}
                          className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-[10px] font-bold transition-all shadow-sm ${expense.status === 'Pago' ? 'bg-emerald-500/20 text-emerald-400 hover:bg-emerald-500/30 ring-1 ring-emerald-500/30' : 'bg-amber-500/20 text-amber-400 hover:bg-amber-500/30 ring-1 ring-amber-500/30'}`}
                        >
                          <div className={`w-1 h-1 rounded-full ${expense.status === 'Pago' ? 'bg-emerald-400' : 'bg-amber-400'}`} />
                          {expense.status.toUpperCase()}
                        </button>
                      </td>
                      <td className="px-2 py-4">
                        <button 
                          onClick={() => removeExpense(expense.id)}
                          className="p-2 text-slate-600 hover:text-red-400 transition-colors opacity-0 group-hover:opacity-100"
                        >
                          <Trash2 className="w-4 h-4" />
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

interface CardProps {
  title: string;
  value: string;
  icon: React.ReactNode;
  comparison?: { value: string; isIncrease: boolean } | null;
}

const Card: React.FC<CardProps> = ({ title, value, icon, comparison }) => {
  return (
    <div className="p-5 rounded-3xl border bg-slate-900 border-slate-800 shadow-sm flex flex-col justify-between transition-transform hover:scale-[1.02] cursor-default group">
      <div className="flex items-center justify-between mb-4">
        <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">{title}</span>
        <div className="p-2 rounded-xl bg-slate-800 group-hover:bg-slate-700 transition-colors">
          {icon}
        </div>
      </div>
      <div>
        <p className="text-2xl font-bold mono tracking-tight text-white mb-1">{value}</p>
        {comparison && (
          <div className="flex items-center gap-1 text-[10px] font-bold">
            {comparison.isIncrease ? (
              <ArrowUpRight className="w-3 h-3 text-red-400" />
            ) : (
              <ArrowDownRight className="w-3 h-3 text-emerald-400" />
            )}
            <span className={comparison.isIncrease ? 'text-red-400' : 'text-emerald-400'}>
              {comparison.value}% que o mês anterior
            </span>
          </div>
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { 
  TrendingUp, 
  TrendingDown, 
  Wallet, 
  Activity, 
  BrainCircuit, 
  Plus, 
  RefreshCw,
  LayoutDashboard,
  Receipt,
  PieChart as PieChartIcon,
  Calendar,
  History,
  ChevronLeft,
  ChevronRight,
  ArrowUpRight,
  ArrowDownRight,
  CheckCircle2,
  Trash2,
  Menu,
  X
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell,
  PieChart,
  Pie,
  AreaChart,
  Area
} from 'recharts';
import { INITIAL_EXPENSES, CATEGORIES } from './constants';
import { Expense, SummaryData, MonthlyDataStore } from './types';
import { getFinancialInsights } from './services/geminiService';

const MONTHS = [
  'Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho',
  'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'
];

const App: React.FC = () => {
  const [selectedMonth, setSelectedMonth] = useState<number>(new Date().getMonth());
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [monthlyStore, setMonthlyStore] = useState<MonthlyDataStore>(() => {
    const savedStore = localStorage.getItem('finance_monthly_store');
    if (savedStore) return JSON.parse(savedStore);

    const oldData = localStorage.getItem('finance_expenses');
    const initialStore: MonthlyDataStore = {};

    MONTHS.forEach((_, index) => {
      if (index === 0 && oldData) {
        initialStore[index] = JSON.parse(oldData);
      } else {
        initialStore[index] = INITIAL_EXPENSES.map(e => ({ 
          ...e, 
          id: `${e.id}-${index}-${Math.random().toString(36).substr(2, 9)}` 
        }));
      }
    });
    return initialStore;
  });

  const [insights, setInsights] = useState<string>("");
  const [loadingInsights, setLoadingInsights] = useState(false);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'list' | 'history'>('dashboard');

  useEffect(() => {
    localStorage.setItem('finance_monthly_store', JSON.stringify(monthlyStore));
  }, [monthlyStore]);

  const expenses = useMemo(() => monthlyStore[selectedMonth] || [], [monthlyStore, selectedMonth]);

  const getMonthSummary = (monthIdx: number): SummaryData => {
    const monthExpenses = monthlyStore[monthIdx] || [];
    const totalExpected = monthExpenses.reduce((acc, curr) => acc + curr.expectedValue, 0);
    const totalPaid = monthExpenses.reduce((acc, curr) => acc + curr.paidValue, 0);
    const fixedTotal = monthExpenses.filter(e => e.type === 'Fixa').reduce((acc, curr) => acc + curr.paidValue, 0);
    const variableTotal = monthExpenses.filter(e => e.type === 'Variável').reduce((acc, curr) => acc + curr.paidValue, 0);

    return {
      totalExpected,
      totalPaid,
      balance: totalExpected - totalPaid,
      progress: totalExpected > 0 ? (totalPaid / totalExpected) * 100 : 0,
      fixedTotal,
      variableTotal
    };
  };

  const currentSummary = useMemo(() => getMonthSummary(selectedMonth), [expenses]);
  const prevSummary = useMemo(() => selectedMonth > 0 ? getMonthSummary(selectedMonth - 1) : null, [monthlyStore, selectedMonth]);

  const historyData = useMemo(() => {
    return MONTHS.map((name, index) => {
      const s = getMonthSummary(index);
      return {
        name: name.substring(0, 3),
        fullName: name,
        pago: s.totalPaid,
        previsto: s.totalExpected,
        economia: s.totalExpected - s.totalPaid > 0 ? s.totalExpected - s.totalPaid : 0,
        index
      };
    });
  }, [monthlyStore]);

  const chartData = useMemo(() => {
    const cats = Array.from(new Set(expenses.map(e => e.category)));
    return cats.map((cat: string) => ({
      name: cat,
      value: expenses.filter(e => e.category === cat).reduce((acc, curr) => acc + curr.paidValue, 0),
      color: CATEGORIES[cat]?.color || '#ccc'
    })).sort((a, b) => b.value - a.value);
  }, [expenses]);

  const handleUpdateExpense = (id: string, field: keyof Expense, value: any) => {
    setMonthlyStore(prev => {
      const newExpenses = prev[selectedMonth].map(e => e.id === id ? { ...e, [field]: value } : e);
      return { ...prev, [selectedMonth]: newExpenses };
    });
  };

  const removeExpense = (id: string) => {
    setMonthlyStore(prev => ({
      ...prev,
      [selectedMonth]: prev[selectedMonth].filter(e => e.id !== id)
    }));
  };

  const toggleStatus = (id: string) => {
    setMonthlyStore(prev => {
      const newExpenses = prev[selectedMonth].map(e => {
        if (e.id === id) {
          const newStatus = e.status === 'Pago' ? 'Pendente' : 'Pago';
          const newPaidValue = newStatus === 'Pago' ? e.expectedValue : 0;
          return { ...e, status: newStatus, paidValue: newPaidValue };
        }
        return e;
      });
      return { ...prev, [selectedMonth]: newExpenses };
    });
  };

  const fetchInsights = async () => {
    setLoadingInsights(true);
    const text = await getFinancialInsights(expenses);
    setInsights(text || "Sem insights disponíveis.");
    setLoadingInsights(false);
  };

  const formatBRL = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const getComparison = (curr: number, prev: number | undefined) => {
    if (prev === undefined || prev === null || prev === 0) return null;
    const diff = ((curr - prev) / prev) * 100;
    return {
      value: Math.abs(diff).toFixed(1),
      isIncrease: diff > 0
    };
  };

  const addNewExpense = () => {
    const newExp: Expense = {
      id: Date.now().toString(),
      description: 'Novo Gasto',
      category: 'Essencial',
      type: 'Variável',
      expectedValue: 0,
      paidValue: 0,
      dueDate: '',
      status: 'Pendente'
    };
    setMonthlyStore(prev => ({ ...prev, [selectedMonth]: [...prev[selectedMonth], newExp] }));
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 flex flex-col md:flex-row overflow-x-hidden">
      {/* Sidebar Mobile Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/60 z-40 md:hidden backdrop-blur-sm transition-opacity"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar Content */}
      <aside className={`fixed md:sticky top-0 left-0 h-screen w-72 bg-slate-900 border-r border-slate-800 flex flex-col z-50 transition-transform duration-300 md:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="p-6">
          <div className="flex items-center justify-between mb-8">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-emerald-500 rounded-lg">
                <Wallet className="w-6 h-6 text-slate-950" />
              </div>
              <h1 className="text-xl font-bold bg-gradient-to-r from-emerald-400 to-cyan-400 bg-clip-text text-transparent">FinanceFlow</h1>
            </div>
            <button onClick={() => setIsSidebarOpen(false)} className="md:hidden p-2 text-slate-400">
              <X className="w-6 h-6" />
            </button>
          </div>

          <nav className="flex flex-col gap-2 mb-8">
            <button 
              onClick={() => { setActiveTab('dashboard'); setIsSidebarOpen(false); }}
              className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'dashboard' ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20' : 'text-slate-400 hover:bg-slate-800'}`}
            >
              <LayoutDashboard className="w-5 h-5" />
              <span className="font-medium">Dashboard</span>
            </button>
            <button 
              onClick={() => { setActiveTab('list'); setIsSidebarOpen(false); }}
              className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'list' ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20' : 'text-slate-400 hover:bg-slate-800'}`}
            >
              <Receipt className="w-5 h-5" />
              <span className="font-medium">Detalhamento</span>
            </button>
            <button 
              onClick={() => { setActiveTab('history'); setIsSidebarOpen(false); }}
              className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'history' ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20' : 'text-slate-400 hover:bg-slate-800'}`}
            >
              <History className="w-5 h-5" />
              <span className="font-medium">Histórico Anual</span>
            </button>
          </nav>

          <div className="space-y-4">
            <p className="text-[10px] font-bold uppercase tracking-widest text-slate-500 px-4">Calendário {new Date().getFullYear()}</p>
            <div className="grid grid-cols-3 gap-2">
              {MONTHS.map((month, idx) => (
                <button
                  key={month}
                  onClick={() => { setSelectedMonth(idx); }}
                  className={`py-2 text-[10px] font-bold rounded-lg border transition-all ${selectedMonth === idx ? 'bg-emerald-500 border-emerald-500 text-slate-950 shadow-lg shadow-emerald-500/20' : 'bg-slate-800/50 border-slate-700 text-slate-400 hover:border-slate-500'}`}
                >
                  {month.substring(0, 3)}
                </button>
              ))}
            </div>
          </div>
        </div>

        <div className="mt-auto p-6 border-t border-slate-800">
          <div className="p-4 bg-slate-800/50 rounded-2xl border border-slate-700/50">
            <p className="text-xs text-slate-400 mb-1">Foco Mensal</p>
            <p className="text-sm font-bold text-white uppercase">{MONTHS[selectedMonth]}</p>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col min-h-screen">
        {/* Mobile Header */}
        <div className="md:hidden flex items-center justify-between p-4 bg-slate-900 border-b border-slate-800 sticky top-0 z-30">
          <button onClick={() => setIsSidebarOpen(true)} className="p-2 text-slate-100">
            <Menu className="w-6 h-6" />
          </button>
          <div className="text-sm font-bold text-emerald-400 uppercase tracking-widest">
            {MONTHS[selectedMonth]}
          </div>
          <button onClick={fetchInsights} disabled={loadingInsights} className="p-2 text-indigo-400">
            <BrainCircuit className={`w-6 h-6 ${loadingInsights ? 'animate-spin' : ''}`} />
          </button>
        </div>

        <div className="p-4 md:p-8 flex-1">
          <header className="hidden md:flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
            <div>
              <div className="flex items-center gap-2 text-emerald-400 text-xs font-bold uppercase tracking-wider mb-1">
                <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
                Gestão Profissional • {MONTHS[selectedMonth]}
              </div>
              <h2 className="text-2xl font-bold text-white">
                {activeTab === 'dashboard' ? 'Visão Geral' : activeTab === 'list' ? 'Lista de Despesas' : 'Análise Histórica'}
              </h2>
            </div>

            <div className="flex items-center gap-3">
              <div className="flex bg-slate-900 rounded-xl p-1 border border-slate-800">
                <button onClick={() => setSelectedMonth(prev => Math.max(0, prev - 1))} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400 transition-colors">
                  <ChevronLeft className="w-5 h-5" />
                </button>
                <div className="px-4 py-2 text-sm font-bold text-slate-200 min-w-[100px] text-center uppercase tracking-wide">
                  {MONTHS[selectedMonth].substring(0, 3)}
                </div>
                <button onClick={() => setSelectedMonth(prev => Math.min(11, prev + 1))} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400 transition-colors">
                  <ChevronRight className="w-5 h-5" />
                </button>
              </div>

              {activeTab !== 'history' && (
                <button 
                  onClick={fetchInsights}
                  disabled={loadingInsights}
                  className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 disabled:bg-indigo-900 rounded-xl font-bold transition-all shadow-lg shadow-indigo-500/20 text-white text-sm"
                >
                  <BrainCircuit className={`w-4 h-4 ${loadingInsights ? 'animate-spin' : ''}`} />
                  Insights IA
                </button>
              )}
            </div>
          </header>

          {activeTab === 'history' ? (
            /* History View */
