    setLoadingInsights(false);
  };

  const formatBRL = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val || 0);

  const getComparison = (curr: number, prev: number | undefined) => {
    if (prev === undefined || prev === null || prev === 0) return null;
    const diff = ((curr - prev) / prev) * 100;
    return {
      value: Math.abs(diff).toFixed(1),
      isIncrease: diff > 0
    };
  };

  const addNewExpense = () => {
    const newExp: Expense = {
      id: Date.now().toString(),
      description: 'Novo Gasto',
      category: 'Essencial',
      type: 'Variável',
      expectedValue: 0,
      paidValue: 0,
      dueDate: '',
      status: 'Pendente'
    };
    setMonthlyStore(prev => ({ 
      ...prev, 
      [selectedMonth]: [...(prev[selectedMonth] || []), newExp] 
    }));
  };

