interface CardProps {
  title: string;
  value: string;
  icon: React.ReactNode;
  comparison?: { value: string; isIncrease: boolean } | null;
}

const Card: React.FC<CardProps> = ({ title, value, icon, comparison }) => {
  return (
    <div className="p-5 rounded-2xl md:rounded-3xl border bg-slate-900 border-slate-800 shadow-sm flex flex-col justify-between transition-transform hover:scale-[1.02] group">
      <div className="flex items-center justify-between mb-4">
        <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">{title}</span>
        <div className="p-2 rounded-xl bg-slate-800 group-hover:bg-slate-700 transition-colors">
          {icon}
        </div>
      </div>
      <div>
        <p className="text-xl md:text-2xl font-bold mono tracking-tight text-white mb-1">{value}</p>
        {comparison && (
          <div className="flex items-center gap-1 text-[10px] font-bold">
            {comparison.isIncrease ? <ArrowUpRight className="w-3 h-3 text-red-400" /> : <ArrowDownRight className="w-3 h-3 text-emerald-400" />}
            <span className={comparison.isIncrease ? 'text-red-400' : 'text-emerald-400'}>{comparison.value}%</span>
          </div>
        )}
      </div>
    </div>
  );
};

export default App;

