import React, { useState, useMemo, useEffect } from 'react';
import { 
  TrendingUp, 
  TrendingDown, 
  Wallet, 
  Activity, 
  BrainCircuit, 
  Plus, 
  RefreshCw,
  LayoutDashboard, 
  Receipt,
  PieChart as PieChartIcon,
  Calendar,
  History,
  X,
  Menu,
  Trash2,
  ArrowUpRight,
  ArrowDownRight,
  Settings,
  Tag,
  PlusCircle,
  Filter
} from 'lucide-react';
