                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={historyData} margin={{ top: 60, right: 10, left: -20, bottom: 0 }}>
                    <defs>
                      <linearGradient id="colorPago" x1="0" y1="0" x2="0" y2="1">
