              <div className="flex gap-3">
                <input 
                  type="text" 
                  placeholder="Nova Categoria..." 
                  value={newCatName}
                  onChange={(e) => setNewCatName(e.target.value)}
                  className="flex-1 bg-slate-950 border border-slate-700 rounded-2xl px-5 py-3 text-sm focus:border-emerald-500 outline-none"
                />
                <input 
                  type="color" 
