                        <td className="px-6 py-5 text-right">
                          <div className="flex items-center justify-end gap-1.5 font-bold mono">
                            <span className="text-slate-600 text-[10px]">R$</span>
                            <input type="number" value={expense.paidValue} onChange={(e) => handleUpdateExpense(expense.id, 'paidValue', parseFloat(e.target.value) || 0)} className="bg-transparent text-right w-24 outline-none text-white font-bold focus:text-emerald-400" />
