                        <td className="px-6 py-5 text-right">
                          <button onClick={() => removeExpense(expense.id)} className="text-slate-600 hover:text-red-400 opacity-0 group-hover:opacity-100 p-2"><Trash2 className="w-4 h-4" /></button>
