                        <input type="number" value={expense.expectedValue} onChange={(e) => handleUpdateExpense(expense.id, 'expectedValue', parseFloat(e.target.value) || 0)} className="bg-transparent font-bold mono text-white w-full outline-none focus:text-emerald-400" />
                      </div>
                      <div className="flex flex-col gap-2 p-4 rounded-2xl bg-slate-800/40 border border-slate-800">
                        <label className="text-[9px] text-slate-500 font-black uppercase">Pago</label>
                        <input type="number" value={expense.paidValue} onChange={(e) => handleUpdateExpense(expense.id, 'paidValue', parseFloat(e.target.value) || 0)} className="bg-transparent font-bold mono text-white w-full outline-none focus:text-emerald-400" />
