                      <button onClick={() => toggleStatus(expense.id)} className={`px-8 py-3 rounded-2xl text-[10px] font-black ${expense.status === 'Pago' ? 'bg-emerald-500 text-slate-950' : 'bg-slate-800 text-amber-500 border border-amber-500/20'}`}>{expense.status.toUpperCase()}</button>
