                <Card title="Média Paga" value={formatBRL(historyData.reduce((acc, curr) => acc + curr.pago, 0) / 12)} icon={<Activity className="text-indigo-400" />} />
                <Card title="Total Previsto" value={formatBRL(historyData.reduce((acc, curr) => acc + curr.previsto, 0))} icon={<TrendingUp className="text-emerald-400" />} />
              </div>
              <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800 h-[450px] shadow-2xl relative">
                <div className="absolute top-6 left-8 text-slate-500 text-[10px] font-bold uppercase">Histórico de Pagamentos Anual</div>
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={historyData} margin={{ top: 60, right: 10, left: -20, bottom: 0 }}>
                    <defs>
                      <linearGradient id="colorPago" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#10b981" stopOpacity={0.1}/>
                        <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" vertical={false} />
                    <XAxis dataKey="name" stroke="#475569" fontSize={10} axisLine={false} tickLine={false} dy={10} />
                    <YAxis stroke="#475569" fontSize={10} axisLine={false} tickLine={false} />
                    <Tooltip contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #1e293b', borderRadius: '16px' }} />
                    <Area type="monotone" dataKey="pago" stroke="#10b981" fill="url(#colorPago)" strokeWidth={4} />
                  </AreaChart>
                </ResponsiveContainer>
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Modal de Categorias */}
      {isCategoryModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/85 backdrop-blur-lg" onClick={() => setIsCategoryModalOpen(false)}></div>
          <div className="relative bg-slate-900 w-full max-w-lg border border-slate-800 rounded-[2.5rem] overflow-hidden shadow-2xl animate-in zoom-in duration-300">
            <div className="p-8 border-b border-slate-800 flex items-center justify-between">
              <h3 className="text-xl font-bold text-white">Categorias</h3>
              <button onClick={() => setIsCategoryModalOpen(false)} className="text-slate-500 hover:text-white transition-all"><X /></button>
            </div>
            <div className="p-8 space-y-6 max-h-[70vh] overflow-y-auto">
              <div className="flex gap-3">
                <input 
                  type="text" 
                  placeholder="Nova Categoria..." 
                  value={newCatName}
                  onChange={(e) => setNewCatName(e.target.value)}
                  className="flex-1 bg-slate-950 border border-slate-700 rounded-2xl px-5 py-3 text-sm focus:border-emerald-500 outline-none"
                />
                <input 
                  type="color" 
                  value={newCatColor}
                  onChange={(e) => setNewCatColor(e.target.value)}
                  className="w-12 h-12 bg-transparent cursor-pointer rounded-2xl overflow-hidden border-none p-0"
                />
                <button onClick={addCategory} className="bg-emerald-500 text-slate-950 px-6 rounded-2xl font-black text-sm hover:bg-emerald-400 transition-all"><Plus className="w-6 h-6" /></button>
              </div>
              <div className="grid grid-cols-1 gap-3">
                {(Object.values(categories) as CategoryInfo[]).map((cat: CategoryInfo) => (
                  <div key={cat.name} className="flex items-center justify-between p-4 bg-slate-800/40 rounded-3xl border border-slate-700/50">
                    <div className="flex items-center gap-4">
                      <div className="w-4 h-4 rounded-full" style={{ backgroundColor: cat.color }}></div>
                      <span className="font-bold text-slate-200">{cat.name}</span>
                    </div>
                    <button onClick={() => removeCategory(cat.name)} className="text-slate-600 hover:text-red-400 transition-colors"><Trash2 className="w-4 h-4" /></button>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Floating Action Button */}
      <button 
        onClick={() => {
          if (activeTab === 'list') {
             addNewExpense();
          } else {
             setActiveTab('list');
          }
        }} 
        className="md:hidden fixed bottom-8 right-8 w-16 h-16 bg-emerald-500 rounded-full flex items-center justify-center text-slate-950 shadow-2xl z-40 active:scale-95 transition-all shadow-emerald-500/40"
      >
        <Plus className="w-9 h-9" />
      </button>
    </div>
  );
};

const Card = ({ title, value, icon }: { title: string, value: string, icon: React.ReactNode }) => (
