import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  TrendingUp, 
  TrendingDown, 
  Wallet, 
  Activity, 
  BrainCircuit, 
  Plus, 
  RefreshCw,
  LayoutDashboard, 
  Receipt,
  PieChart as PieChartIcon,
  Calendar,
  History,
  X,
  Menu,
  Trash2,
  ArrowUpRight,
  ArrowDownRight,
  Settings,
  Tag,
  PlusCircle,
  Filter,
  Download,
  Upload,
  CheckCircle2,
  AlertCircle,
  FileSpreadsheet
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell,
  PieChart,
  Pie,
  AreaChart,
  Area
} from 'recharts';
import * as XLSX from 'xlsx';
import { INITIAL_EXPENSES, CATEGORIES as DEFAULT_CATEGORIES } from './constants';
import { Expense, SummaryData, MonthlyDataStore, ExpenseStatus, CategoryInfo } from './types';
import { getFinancialInsights } from './services/geminiService';

const MONTHS = [
  'Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho',
  'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'
];

const APP_VERSION = "3.7"; 

const App: React.FC = () => {
  const [selectedMonth, setSelectedMonth] = useState<number>(new Date().getMonth());
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isCategoryModalOpen, setIsCategoryModalOpen] = useState(false);
  const [newCatName, setNewCatName] = useState('');
  const [newCatColor, setNewCatColor] = useState('#10b981');
  const [filterCategory, setFilterCategory] = useState<string | null>(null);
  const [showSaveIndicator, setShowSaveIndicator] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [categories, setCategories] = useState<Record<string, CategoryInfo>>(() => {
    const saved = localStorage.getItem('finance_categories');
    return saved ? JSON.parse(saved) : DEFAULT_CATEGORIES;
  });

  const [monthlyStore, setMonthlyStore] = useState<MonthlyDataStore>(() => {
    try {
      const savedStore = localStorage.getItem('finance_monthly_store');
      const savedVersion = localStorage.getItem('finance_app_version');

      if (savedStore && savedVersion === APP_VERSION) {
        return JSON.parse(savedStore);
      }

      const initialStore: MonthlyDataStore = {};
      MONTHS.forEach((_, index) => {
        initialStore[index] = {
          expenses: INITIAL_EXPENSES.map(e => {
            const expVal = index === 0 ? e.expectedValue : 0;
            const paidVal = index === 0 ? e.paidValue : 0;
            const status: ExpenseStatus = (expVal > 0 && paidVal === expVal) ? 'Pago' : 'Pendente';

            return { 
              ...e, 
              groupId: e.id,
              id: `${e.id}-${index}`,
              expectedValue: expVal,
              paidValue: paidVal,
              status: status
            };
          }),
          userName: ''
        };
      });

      localStorage.setItem('finance_app_version', APP_VERSION);
      return initialStore;
    } catch (e) {
      return {};
    }
  });

  const [insights, setInsights] = useState<string>("");
  const [loadingInsights, setLoadingInsights] = useState(false);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'list' | 'history'>('dashboard');

  useEffect(() => {
    localStorage.setItem('finance_monthly_store', JSON.stringify(monthlyStore));
    setShowSaveIndicator(true);
    const timer = setTimeout(() => setShowSaveIndicator(false), 2000);
    return () => clearTimeout(timer);
  }, [monthlyStore]);

  useEffect(() => {
    localStorage.setItem('finance_categories', JSON.stringify(categories));
  }, [categories]);

  const currentMonthData = useMemo(() => monthlyStore[selectedMonth] || { expenses: [], userName: '' }, [monthlyStore, selectedMonth]);
  const expenses = currentMonthData.expenses;

  const filteredExpenses = useMemo(() => {
    if (!filterCategory) return expenses;
    return expenses.filter(e => e.category === filterCategory);
  }, [expenses, filterCategory]);

  const getMonthSummary = (monthIdx: number): SummaryData => {
    const data = monthlyStore[monthIdx];
    const monthExpenses = data ? data.expenses : [];
    const totalExpected = monthExpenses.reduce((acc, curr) => acc + (curr.expectedValue || 0), 0);
    const totalPaid = monthExpenses.reduce((acc, curr) => acc + (curr.paidValue || 0), 0);
    const fixedTotal = monthExpenses.filter(e => e.type === 'Fixa').reduce((acc, curr) => acc + (curr.paidValue || 0), 0);
    const variableTotal = monthExpenses.filter(e => e.type === 'Variável').reduce((acc, curr) => acc + (curr.paidValue || 0), 0);

    return {
      totalExpected,
      totalPaid,
      balance: totalExpected - totalPaid,
      progress: totalExpected > 0 ? (totalPaid / totalExpected) * 100 : 0,
      fixedTotal,
      variableTotal
    };
  };

  const currentSummary = useMemo(() => getMonthSummary(selectedMonth), [monthlyStore, selectedMonth]);

  const historyData = useMemo(() => {
    return MONTHS.map((name, index) => {
      const s = getMonthSummary(index);
      return {
        name: name.substring(0, 3),
        fullName: name,
        pago: s.totalPaid,
        previsto: s.totalExpected,
        economia: s.totalExpected - s.totalPaid > 0 ? s.totalExpected - s.totalPaid : 0,
        index
      };
    });
  }, [monthlyStore]);

  const chartData = useMemo(() => {
    const cats = Array.from(new Set(expenses.map(e => e.category)));
    return cats.map((cat: string) => ({
      name: cat,
      value: expenses.filter(e => e.category === cat).reduce((acc, curr) => acc + (curr.paidValue || 0), 0),
      color: categories[cat]?.color || '#ccc'
    })).sort((a, b) => b.value - a.value);
  }, [expenses, categories]);

  const handleUpdateUserName = (name: string) => {
    setMonthlyStore(prev => ({
      ...prev,
      [selectedMonth]: { ...prev[selectedMonth], userName: name }
    }));
  };

  const handleUpdateExpense = (id: string, field: keyof Expense, value: any) => {
    setMonthlyStore(prev => {
      const newStore = { ...prev };
      const currentMonthData = prev[selectedMonth];
      if (!currentMonthData) return prev;

      const currentMonthExpenses = currentMonthData.expenses;
      const targetExpenseIndex = currentMonthExpenses.findIndex(e => e.id === id);

      if (targetExpenseIndex === -1) return prev;
      const currentExpense = currentMonthExpenses[targetExpenseIndex];

      if (field === 'description' || field === 'category') {
        const gid = currentExpense.groupId;
        for (let i = 0; i < 12; i++) {
          newStore[i] = {
            ...newStore[i],
            expenses: newStore[i].expenses.map(e => 
              e.groupId === gid ? { ...e, [field]: value } : e
            )
          };
        }
      } else {
        newStore[selectedMonth] = {
          ...newStore[selectedMonth],
          expenses: currentMonthExpenses.map(e => {
            if (e.id === id) {
              const updated = { ...e, [field]: value };
              const expVal = field === 'expectedValue' ? (parseFloat(value) || 0) : e.expectedValue;
              const paidVal = field === 'paidValue' ? (parseFloat(value) || 0) : e.paidValue;

              const status: ExpenseStatus = (expVal > 0 && paidVal === expVal) ? 'Pago' : 'Pendente';
              updated.status = status;

              return updated;
            }
            return e;
          })
        };
      }
      return newStore;
    });
  };

  const removeExpense = (id: string) => {
    const expenseToRemove = expenses.find(e => e.id === id);
    if (!expenseToRemove) return;

    if (confirm(`Remover "${expenseToRemove.description}" de TODOS os meses do ano?`)) {
      const gid = expenseToRemove.groupId;
      setMonthlyStore(prev => {
        const newStore = { ...prev };
        for (let i = 0; i < 12; i++) {
          newStore[i] = {
            ...newStore[i],
            expenses: newStore[i].expenses.filter(e => e.groupId !== gid)
          };
        }
        return newStore;
      });
    }
  };

  const toggleStatus = (id: string) => {
    setMonthlyStore(prev => {
      const monthData = prev[selectedMonth];
      if (!monthData) return prev;

      const newExpenses = monthData.expenses.map(e => {
        if (e.id === id) {
          const isMarkingPaid = e.status !== 'Pago';
          return { 
            ...e, 
            status: (isMarkingPaid ? 'Pago' : 'Pendente') as ExpenseStatus, 
            paidValue: isMarkingPaid ? (e.expectedValue > 0 ? e.expectedValue : 0) : 0 
          };
        }
        return e;
      });
      return { ...prev, [selectedMonth]: { ...monthData, expenses: newExpenses } };
    });
  };

  const addNewExpense = (catName?: string) => {
    const baseCategory = catName || Object.keys(categories)[0] || 'Geral';
    const baseDescription = catName || 'Novo Gasto';
    const baseGroupId = `group-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;

    setMonthlyStore(prev => {
      const newStore = { ...prev };
      for (let i = 0; i < 12; i++) {
        const monthData = newStore[i] || { expenses: [], userName: '' };
        const newExp: Expense = {
          id: `${baseGroupId}-${i}`,
          groupId: baseGroupId,
          description: baseDescription,
          category: baseCategory,
          type: 'Variável',
          expectedValue: 0,
          paidValue: 0,
          dueDate: '',
          status: 'Pendente' as ExpenseStatus
        };
        newStore[i] = {
          ...monthData,
          expenses: [...monthData.expenses, newExp]
        };
      }
      return newStore;
    });

    setActiveTab('list');
    setIsCategoryModalOpen(false);
  };

  const addCategory = () => {
    if (!newCatName.trim()) return;
    const catName = newCatName.trim();
    setCategories(prev => ({
      ...prev,
      [catName]: { name: catName, color: newCatColor }
    }));
    addNewExpense(catName);
    setNewCatName('');
  };

  const removeCategory = (name: string) => {
    if (confirm(`Remover a categoria "${name}"? Os gastos existentes não serão excluídos.`)) {
      const newCats = { ...categories };
      delete newCats[name];
      setCategories(newCats);
    }
  };

  const exportMonthToExcel = () => {
    const rows: any[] = [];
    const monthName = MONTHS[selectedMonth];
    const monthData = monthlyStore[selectedMonth];

    if (monthData && monthData.expenses.length > 0) {
      monthData.expenses.forEach(exp => {
        rows.push({
          'Mês': monthName,
          'Responsável': monthData.userName || '-',
          'Descrição': exp.description,
          'Categoria': exp.category,
          'Tipo': exp.type,
          'Valor Previsto (R$)': exp.expectedValue,
          'Valor Pago (R$)': exp.paidValue,
          'Dia Vencimento': exp.dueDate || '-',
          'Status': exp.status
        });
      });

      const worksheet = XLSX.utils.json_to_sheet(rows);
      const workbook = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(workbook, worksheet, `FinanceFlow_${monthName}`);

      const fileName = `FinanceFlow_${monthName}_${new Date().getFullYear()}.xlsx`;
      XLSX.writeFile(workbook, fileName);
    } else {
      alert("Não há lançamentos para exportar neste mês.");
    }
  };

  const exportFullBackupJSON = () => {
    const data = {
      monthlyStore,
      categories,
      exportDate: new Date().toISOString(),
      version: APP_VERSION
    };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `financeflow-full-backup.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const importData = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const content = e.target?.result as string;
        const imported = JSON.parse(content);
        if (imported.monthlyStore && imported.categories) {
          setMonthlyStore(imported.monthlyStore);
          setCategories(imported.categories);
          alert("Backup restaurado com sucesso!");
        }
      } catch (err) {
        alert("Erro ao importar backup.");
      }
    };
    reader.readAsText(file);
  };

  const fetchInsights = async () => {
    setLoadingInsights(true);
    const text = await getFinancialInsights(expenses);
    setInsights(text || "Nenhum insight disponível.");
    setLoadingInsights(false);
  };

  const formatBRL = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val || 0);

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 flex flex-col md:flex-row overflow-x-hidden">
      {/* Sidebar */}
      <aside className={`fixed md:sticky top-0 left-0 h-screen w-72 bg-slate-900 border-r border-slate-800 flex flex-col z-50 transition-transform duration-300 md:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="p-6 flex flex-col h-full">
          <div className="flex items-center justify-between mb-8">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-emerald-500 rounded-lg shadow-lg shadow-emerald-500/20">
                <Wallet className="w-6 h-6 text-slate-950" />
              </div>
              <h1 className="text-xl font-bold bg-gradient-to-r from-emerald-400 to-cyan-400 bg-clip-text text-transparent">FinanceFlow</h1>
            </div>
            <button onClick={() => setIsSidebarOpen(false)} className="md:hidden p-2 text-slate-400"><X /></button>
          </div>

          <nav className="flex flex-col gap-2 mb-8">
            <button onClick={() => { setActiveTab('dashboard'); setIsSidebarOpen(false); }} className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'dashboard' ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20' : 'text-slate-400 hover:bg-slate-800'}`}>
              <LayoutDashboard className="w-5 h-5" /> Dashboard
            </button>
            <button onClick={() => { setActiveTab('list'); setIsSidebarOpen(false); }} className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'list' ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20' : 'text-slate-400 hover:bg-slate-800'}`}>
              <Receipt className="w-5 h-5" /> Gastos
            </button>
            <button onClick={() => { setActiveTab('history'); setIsSidebarOpen(false); }} className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'history' ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20' : 'text-slate-400 hover:bg-slate-800'}`}>
              <History className="w-5 h-5" /> Histórico
            </button>
          </nav>

          <div className="space-y-4 mb-auto overflow-y-auto custom-scrollbar">
            <p className="text-[10px] font-bold uppercase tracking-widest text-slate-500 px-4">Calendário Anual</p>
            <div className="grid grid-cols-3 gap-2 px-2">
              {MONTHS.map((month, idx) => (
                <button key={month} onClick={() => setSelectedMonth(idx)} className={`py-2 text-[10px] font-bold rounded-lg border transition-all ${selectedMonth === idx ? 'bg-emerald-500 border-emerald-500 text-slate-950 shadow-lg shadow-emerald-500/20' : 'bg-slate-800/50 border-slate-700 text-slate-400 hover:border-slate-500'}`}>
                  {month.substring(0, 3)}
                </button>
              ))}
            </div>
          </div>

          <div className="pt-6 border-t border-slate-800 mt-6 space-y-4">
            <p className="text-[10px] font-bold uppercase tracking-widest text-slate-500 px-4">Exportação e Dados</p>
            <div className="flex flex-col gap-2 px-2">
              <button onClick={exportMonthToExcel} className="flex items-center justify-between gap-2 px-4 py-2.5 bg-emerald-500/10 text-emerald-400 rounded-xl text-xs font-bold border border-emerald-500/20 hover:bg-emerald-500 hover:text-slate-950 transition-all">
                Exportar {MONTHS[selectedMonth]} (.xlsx) <FileSpreadsheet className="w-4 h-4" />
              </button>
              <button onClick={exportFullBackupJSON} className="flex items-center justify-between gap-2 px-4 py-2.5 bg-slate-800/50 text-slate-300 rounded-xl text-xs font-bold border border-slate-700 hover:bg-slate-800 hover:text-white transition-all">
                Backup GERAL <Download className="w-4 h-4" />
              </button>
              <button onClick={() => fileInputRef.current?.click()} className="flex items-center justify-between gap-2 px-4 py-2.5 bg-slate-800/50 text-slate-300 rounded-xl text-xs font-bold border border-slate-700 hover:bg-slate-800 hover:text-white transition-all">
                Restaurar Backup <Upload className="w-4 h-4" />
              </button>
              <input type="file" ref={fileInputRef} onChange={importData} accept=".json" className="hidden" />
            </div>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col min-h-screen">
        <div className="flex items-center justify-between p-4 bg-slate-900 border-b border-slate-800 sticky top-0 z-30 shadow-md">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(true)} className="md:hidden p-2 text-slate-100 bg-slate-800 rounded-lg"><Menu /></button>
            <div className="flex items-center gap-2">
              <span className="text-sm font-black text-white uppercase tracking-widest">{MONTHS[selectedMonth]}</span>
              {showSaveIndicator && (
                <span className="flex items-center gap-1 text-[9px] text-emerald-400 font-bold bg-emerald-500/10 px-2 py-0.5 rounded-full animate-pulse border border-emerald-500/20">
                  <CheckCircle2 className="w-3 h-3" /> AUTO-SALVO
                </span>
              )}
            </div>
          </div>
          <div className="flex items-center gap-2">
            <button onClick={fetchInsights} disabled={loadingInsights} className="p-2.5 bg-indigo-500/10 text-indigo-400 rounded-xl border border-indigo-500/20 hover:bg-indigo-500/20 transition-all flex items-center gap-2">
              <span className="hidden sm:inline text-xs font-bold uppercase tracking-widest">Insights IA</span>
              <BrainCircuit className={`w-5 h-5 ${loadingInsights ? 'animate-spin' : ''}`} />
            </button>
          </div>
        </div>

        <div className="p-4 md:p-8 flex-1">
          {activeTab === 'dashboard' ? (
            <div className="space-y-6 animate-in fade-in duration-500">
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                <Card title="Previsto" value={formatBRL(currentSummary.totalExpected)} icon={<TrendingUp className="text-blue-400" />} />
                <Card title="Pago" value={formatBRL(currentSummary.totalPaid)} icon={<TrendingDown className="text-emerald-400" />} />
                <Card title="Saldo Restante" value={formatBRL(currentSummary.balance)} icon={<Wallet className="text-amber-400" />} />
                <div className="bg-slate-900 p-5 rounded-2xl border border-slate-800 flex flex-col justify-between shadow-lg">
                  <div className="flex items-center justify-between mb-2">
                    <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Execução</span>
                    <Activity className="w-5 h-5 text-purple-400" />
                  </div>
                  <div className="flex flex-col gap-2">
                    <span className="text-2xl font-bold mono text-white">{Math.round(currentSummary.progress)}%</span>
                    <div className="h-2 bg-slate-800 rounded-full overflow-hidden">
                      <div className="h-full bg-gradient-to-r from-emerald-500 to-indigo-500" style={{ width: `${currentSummary.progress}%` }} />
                    </div>
                  </div>
                </div>
              </div>

              {insights && (
                <div className="bg-indigo-500/10 border border-indigo-500/20 rounded-3xl p-6 shadow-xl relative overflow-hidden group">
                  <div className="absolute top-0 right-0 p-8 opacity-5 group-hover:scale-110 transition-transform"><BrainCircuit className="w-24 h-24 text-indigo-400" /></div>
                  <h3 className="font-bold text-indigo-300 flex items-center gap-2 mb-4"><BrainCircuit className="w-5 h-5" /> Inteligência Financeira Gemini</h3>
                  <div className="prose prose-invert max-w-none text-slate-200 text-sm leading-relaxed relative z-10">{insights.split('\n').map((l, i) => <p key={i} className="mb-2">{l}</p>)}</div>
                </div>
              )}

              <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                <div className="bg-slate-900 p-6 rounded-3xl border border-slate-800 shadow-2xl">
                  <h3 className="font-bold text-white mb-6 flex items-center gap-2"><PieChartIcon className="w-5 h-5 text-cyan-400" /> Divisão por Categoria</h3>
                  <div className="h-[250px]">
                    <ResponsiveContainer width="100%" height="100%">
                      <BarChart data={chartData} layout="vertical">
                        <XAxis type="number" hide />
                        <YAxis dataKey="name" type="category" stroke="#94a3b8" fontSize={10} width={80} axisLine={false} tickLine={false} />
                        <Tooltip cursor={{fill: '#1e293b'}} contentStyle={{backgroundColor: '#0f172a', border: '1px solid #1e293b', borderRadius: '12px'}} />
                        <Bar dataKey="value" radius={[0, 8, 8, 0]} barSize={24}>
                          {chartData.map((entry, index) => <Cell key={`cell-${index}`} fill={entry.color} />)}
                        </Bar>
                      </BarChart>
                    </ResponsiveContainer>
                  </div>
                </div>
                <div className="bg-slate-900 p-6 rounded-3xl border border-slate-800 shadow-2xl flex flex-col items-center">
                  <h3 className="font-bold text-white mb-6 w-full flex items-center gap-2"><RefreshCw className="w-5 h-5 text-pink-400" /> Tipos de Lançamento</h3>
                  <div className="h-[200px] w-full relative">
                    <ResponsiveContainer width="100%" height="100%">
                      <PieChart>
                        <Pie data={[{ name: 'Fixas', value: currentSummary.fixedTotal }, { name: 'Variáveis', value: currentSummary.variableTotal }]} innerRadius={60} outerRadius={85} paddingAngle={8} dataKey="value" stroke="none">
                          <Cell fill="#22d3ee" /><Cell fill="#f472b6" />
                        </Pie>
                        <Tooltip contentStyle={{backgroundColor: '#0f172a', border: '1px solid #1e293b', borderRadius: '12px'}} />
                      </PieChart>
                    </ResponsiveContainer>
                    <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                       <span className="text-[10px] text-slate-500 font-bold uppercase">Restante</span>
                       <span className="text-sm font-bold text-white">{formatBRL(currentSummary.balance)}</span>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          ) : activeTab === 'list' ? (
            <div className="space-y-4 pb-24 md:pb-0 animate-in slide-in-from-bottom duration-300">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-slate-900 p-5 rounded-2xl border border-slate-800 shadow-xl">
                <div className="flex items-center gap-4 flex-1">
                  <h3 className="font-bold text-white text-lg">Lançamentos de {MONTHS[selectedMonth]}</h3>
                  <div className="h-8 w-px bg-slate-800 hidden md:block"></div>
                  <div className="flex items-center gap-2 flex-1 max-w-sm">
                    <input 
                      type="text" 
                      placeholder="Identificação do usuário..." 
                      value={currentMonthData.userName}
                      onChange={(e) => handleUpdateUserName(e.target.value)}
                      className="bg-slate-800/50 border border-slate-700/50 rounded-xl px-4 py-2 text-sm font-medium text-emerald-400 focus:outline-none focus:border-emerald-500/50 w-full"
                    />
                  </div>
                </div>
                <div className="flex items-center gap-3">
                  <button onClick={() => setIsCategoryModalOpen(true)} className="flex items-center justify-center gap-2 px-5 py-2.5 bg-slate-800 text-slate-300 rounded-xl text-sm font-bold border border-slate-700 hover:bg-slate-700 transition-all shadow-lg active:scale-95"><Tag className="w-4 h-4" /> Categorias</button>
                  <button onClick={() => addNewExpense()} className="flex items-center justify-center gap-2 px-6 py-2.5 bg-emerald-500 text-slate-950 rounded-xl text-sm font-bold border border-emerald-400/20 hover:bg-emerald-400 transition-all shadow-lg active:scale-95"><Plus className="w-4 h-4" /> Novo Gasto</button>
                </div>
              </div>

              {/* Tabela Desktop */}
              <div className="hidden md:block bg-slate-900 rounded-3xl border border-slate-800 overflow-hidden shadow-2xl">
                <table className="w-full text-left">
                  <thead className="bg-slate-950/50 text-slate-500 text-[10px] uppercase font-bold tracking-widest border-b border-slate-800">
                    <tr>
                      <th className="px-8 py-6">Descrição</th>
                      <th className="px-6 py-6">Categoria</th>
                      <th className="px-6 py-6 text-right">Previsto</th>
                      <th className="px-6 py-6 text-right">Pago</th>
                      <th className="px-6 py-6 text-center">Venc.</th>
                      <th className="px-6 py-6 text-center">Status</th>
                      <th className="px-6 py-6 text-right">Ação</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-800/40">
                    {filteredExpenses.map((expense) => (
                      <tr key={expense.id} className="hover:bg-slate-800/20 transition-colors group">
                        <td className="px-8 py-5">
                          <input type="text" value={expense.description} onChange={(e) => handleUpdateExpense(expense.id, 'description', e.target.value)} className="bg-transparent text-white font-bold outline-none w-full focus:text-emerald-400" />
                        </td>
                        <td className="px-6 py-5">
                          <select value={expense.category} onChange={(e) => handleUpdateExpense(expense.id, 'category', e.target.value)} className="bg-transparent text-xs font-bold outline-none cursor-pointer" style={{ color: categories[expense.category]?.color || '#fff' }}>
                            {Object.keys(categories).map(c => <option key={c} value={c} className="bg-slate-900" style={{ color: categories[c]?.color }}>{c}</option>)}
                          </select>
                        </td>
                        <td className="px-6 py-5 text-right">
                          <div className="flex items-center justify-end gap-1.5 font-bold mono">
                            <span className="text-slate-600 text-[10px]">R$</span>
                            <input type="number" value={expense.expectedValue} onChange={(e) => handleUpdateExpense(expense.id, 'expectedValue', parseFloat(e.target.value) || 0)} className="bg-transparent text-right w-24 outline-none text-white font-bold focus:text-emerald-400" />
                          </div>
                        </td>
                        <td className="px-6 py-5 text-right">
                          <div className="flex items-center justify-end gap-1.5 font-bold mono">
                            <span className="text-slate-600 text-[10px]">R$</span>
                            <input type="number" value={expense.paidValue} onChange={(e) => handleUpdateExpense(expense.id, 'paidValue', parseFloat(e.target.value) || 0)} className="bg-transparent text-right w-24 outline-none text-white font-bold focus:text-emerald-400" />
                          </div>
                        </td>
                        <td className="px-6 py-5 text-center">
                          <input type="text" value={expense.dueDate} maxLength={2} placeholder="--" onChange={(e) => handleUpdateExpense(expense.id, 'dueDate', e.target.value)} className="bg-transparent text-center w-8 outline-none text-slate-400 font-bold focus:text-white" />
                        </td>
                        <td className="px-6 py-5 text-center">
                          <button onClick={() => toggleStatus(expense.id)} className={`px-4 py-1.5 rounded-full text-[10px] font-black transition-all ${expense.status === 'Pago' ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20 shadow-lg shadow-emerald-500/10' : 'bg-amber-500/10 text-amber-400 border border-amber-500/20 shadow-lg shadow-amber-500/10'}`}>{expense.status.toUpperCase()}</button>
                        </td>
                        <td className="px-6 py-5 text-right">
                          <button onClick={() => removeExpense(expense.id)} className="text-slate-600 hover:text-red-400 opacity-0 group-hover:opacity-100 p-2"><Trash2 className="w-4 h-4" /></button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>

              {/* Mobile View */}
              <div className="grid grid-cols-1 gap-4 md:hidden">
                {filteredExpenses.map((expense) => (
                  <div key={expense.id} className="bg-slate-900 border border-slate-800 rounded-3xl p-6 space-y-4 shadow-xl relative" style={{ borderLeft: `6px solid ${categories[expense.category]?.color || '#475569'}` }}>
                    <div className="flex justify-between items-start">
                      <div className="flex flex-col gap-1.5 w-full">
                        <input type="text" value={expense.description} onChange={(e) => handleUpdateExpense(expense.id, 'description', e.target.value)} className="bg-transparent text-white font-bold text-lg outline-none focus:text-emerald-400" />
                        <span className="text-[9px] font-black uppercase text-slate-500">{expense.category} | {expense.type}</span>
                      </div>
                      <button onClick={() => removeExpense(expense.id)} className="text-slate-600 p-2"><Trash2 className="w-5 h-5" /></button>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div className="flex flex-col gap-2 p-4 rounded-2xl bg-slate-800/40 border border-slate-800">
                        <label className="text-[9px] text-slate-500 font-black uppercase">Previsto</label>
                        <input type="number" value={expense.expectedValue} onChange={(e) => handleUpdateExpense(expense.id, 'expectedValue', parseFloat(e.target.value) || 0)} className="bg-transparent font-bold mono text-white w-full outline-none focus:text-emerald-400" />
                      </div>
                      <div className="flex flex-col gap-2 p-4 rounded-2xl bg-slate-800/40 border border-slate-800">
                        <label className="text-[9px] text-slate-500 font-black uppercase">Pago</label>
                        <input type="number" value={expense.paidValue} onChange={(e) => handleUpdateExpense(expense.id, 'paidValue', parseFloat(e.target.value) || 0)} className="bg-transparent font-bold mono text-white w-full outline-none focus:text-emerald-400" />
                      </div>
                    </div>
                    <div className="flex justify-between items-center pt-4 border-t border-slate-800/50">
                      <input type="text" value={expense.dueDate} maxLength={2} placeholder="Dia" onChange={(e) => handleUpdateExpense(expense.id, 'dueDate', e.target.value)} className="bg-transparent text-xs font-bold text-slate-400 w-10 outline-none" />
                      <button onClick={() => toggleStatus(expense.id)} className={`px-8 py-3 rounded-2xl text-[10px] font-black ${expense.status === 'Pago' ? 'bg-emerald-500 text-slate-950' : 'bg-slate-800 text-amber-500 border border-amber-500/20'}`}>{expense.status.toUpperCase()}</button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ) : (
            <div className="space-y-6 animate-in fade-in duration-300">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <Card title="Acumulado Pago" value={formatBRL(historyData.reduce((acc, curr) => acc + curr.pago, 0))} icon={<ArrowUpRight className="text-emerald-400" />} />
                <Card title="Média Paga" value={formatBRL(historyData.reduce((acc, curr) => acc + curr.pago, 0) / 12)} icon={<Activity className="text-indigo-400" />} />
                <Card title="Total Previsto" value={formatBRL(historyData.reduce((acc, curr) => acc + curr.previsto, 0))} icon={<TrendingUp className="text-emerald-400" />} />
              </div>
              <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800 h-[450px] shadow-2xl relative">
                <div className="absolute top-6 left-8 text-slate-500 text-[10px] font-bold uppercase">Histórico de Pagamentos Anual</div>
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={historyData} margin={{ top: 60, right: 10, left: -20, bottom: 0 }}>
                    <defs>
                      <linearGradient id="colorPago" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#10b981" stopOpacity={0.1}/>
                        <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" vertical={false} />
                    <XAxis dataKey="name" stroke="#475569" fontSize={10} axisLine={false} tickLine={false} dy={10} />
                    <YAxis stroke="#475569" fontSize={10} axisLine={false} tickLine={false} />
                    <Tooltip contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #1e293b', borderRadius: '16px' }} />
                    <Area type="monotone" dataKey="pago" stroke="#10b981" fill="url(#colorPago)" strokeWidth={4} />
                  </AreaChart>
                </ResponsiveContainer>
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Modal de Categorias */}
      {isCategoryModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/85 backdrop-blur-lg" onClick={() => setIsCategoryModalOpen(false)}></div>
          <div className="relative bg-slate-900 w-full max-w-lg border border-slate-800 rounded-[2.5rem] overflow-hidden shadow-2xl animate-in zoom-in duration-300">
            <div className="p-8 border-b border-slate-800 flex items-center justify-between">
              <h3 className="text-xl font-bold text-white">Categorias</h3>
              <button onClick={() => setIsCategoryModalOpen(false)} className="text-slate-500 hover:text-white transition-all"><X /></button>
            </div>
            <div className="p-8 space-y-6 max-h-[70vh] overflow-y-auto">
              <div className="flex gap-3">
                <input 
                  type="text" 
                  placeholder="Nova Categoria..." 
                  value={newCatName}
                  onChange={(e) => setNewCatName(e.target.value)}
                  className="flex-1 bg-slate-950 border border-slate-700 rounded-2xl px-5 py-3 text-sm focus:border-emerald-500 outline-none"
                />
                <input 
                  type="color" 
                  value={newCatColor}
                  onChange={(e) => setNewCatColor(e.target.value)}
                  className="w-12 h-12 bg-transparent cursor-pointer rounded-2xl overflow-hidden border-none p-0"
                />
                <button onClick={addCategory} className="bg-emerald-500 text-slate-950 px-6 rounded-2xl font-black text-sm hover:bg-emerald-400 transition-all"><Plus className="w-6 h-6" /></button>
              </div>
              <div className="grid grid-cols-1 gap-3">
                {(Object.values(categories) as CategoryInfo[]).map((cat: CategoryInfo) => (
                  <div key={cat.name} className="flex items-center justify-between p-4 bg-slate-800/40 rounded-3xl border border-slate-700/50">
                    <div className="flex items-center gap-4">
                      <div className="w-4 h-4 rounded-full" style={{ backgroundColor: cat.color }}></div>
                      <span className="font-bold text-slate-200">{cat.name}</span>
                    </div>
                    <button onClick={() => removeCategory(cat.name)} className="text-slate-600 hover:text-red-400 transition-colors"><Trash2 className="w-4 h-4" /></button>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Floating Action Button */}
      <button 
        onClick={() => {
          if (activeTab === 'list') {
             addNewExpense();
          } else {
             setActiveTab('list');
          }
        }} 
        className="md:hidden fixed bottom-8 right-8 w-16 h-16 bg-emerald-500 rounded-full flex items-center justify-center text-slate-950 shadow-2xl z-40 active:scale-95 transition-all shadow-emerald-500/40"
      >
        <Plus className="w-9 h-9" />
      </button>
    </div>
  );
};

const Card = ({ title, value, icon }: { title: string, value: string, icon: React.ReactNode }) => (
  <div className="bg-slate-900 p-6 rounded-3xl border border-slate-800 flex flex-col justify-between hover:border-slate-700 transition-all group shadow-xl">
    <div className="flex justify-between items-start mb-6">
      <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-none">{title}</span>
      <div className="p-3 bg-slate-800 rounded-2xl group-hover:scale-110 group-hover:bg-slate-700 transition-all">{icon}</div>
    </div>
    <div className="text-xl md:text-2xl font-bold mono text-white truncate">{value}</div>
  </div>
);

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  TrendingUp, 
  TrendingDown, 
  Wallet, 
  Activity, 
  BrainCircuit, 
  Plus, 
  RefreshCw,
  LayoutDashboard, 
  Receipt,
  PieChart as PieChartIcon,
  Calendar,
  History,
  X,
  Menu,
  Trash2,
  ArrowUpRight,
  ArrowDownRight,
  Settings,
  Tag,
  PlusCircle,
  Filter,
  Download,
  Upload,
  CheckCircle2,
  AlertCircle,
  FileSpreadsheet,
  Lock,
  Unlock,
  LogOut
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell,
  PieChart,
  Pie,
  AreaChart,
  Area
} from 'recharts';
import * as XLSX from 'xlsx';
import { INITIAL_EXPENSES, CATEGORIES as DEFAULT_CATEGORIES } from './constants';
import { Expense, SummaryData, MonthlyDataStore, ExpenseStatus, CategoryInfo } from './types';
import { getFinancialInsights } from './services/geminiService';

const MONTHS = [
  'Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho',
  'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'
];

const APP_VERSION = "3.8"; 

const App: React.FC = () => {
  // --- Estados de Autenticação ---
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    return sessionStorage.getItem('finance_auth') === 'true';
  });
  const [passwordInput, setPasswordInput] = useState('');
  const [authError, setAuthError] = useState(false);
  const [isSettingPassword, setIsSettingPassword] = useState(() => {
    return !localStorage.getItem('finance_app_pwd');
  });

  // --- Estados do App ---
  const [selectedMonth, setSelectedMonth] = useState<number>(new Date().getMonth());
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isCategoryModalOpen, setIsCategoryModalOpen] = useState(false);
  const [newCatName, setNewCatName] = useState('');
  const [newCatColor, setNewCatColor] = useState('#10b981');
  const [filterCategory, setFilterCategory] = useState<string | null>(null);
  const [showSaveIndicator, setShowSaveIndicator] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [categories, setCategories] = useState<Record<string, CategoryInfo>>(() => {
    const saved = localStorage.getItem('finance_categories');
    return saved ? JSON.parse(saved) : DEFAULT_CATEGORIES;
  });

  const [monthlyStore, setMonthlyStore] = useState<MonthlyDataStore>(() => {
    try {
      const savedStore = localStorage.getItem('finance_monthly_store');
      const savedVersion = localStorage.getItem('finance_app_version');

      if (savedStore && savedVersion === APP_VERSION) {
        return JSON.parse(savedStore);
      }

      const initialStore: MonthlyDataStore = {};
      MONTHS.forEach((_, index) => {
        initialStore[index] = {
          expenses: INITIAL_EXPENSES.map(e => {
            const expVal = index === 0 ? e.expectedValue : 0;
            const paidVal = index === 0 ? e.paidValue : 0;
            const status: ExpenseStatus = (expVal > 0 && paidVal === expVal) ? 'Pago' : 'Pendente';

            return { 
              ...e, 
              groupId: e.id,
              id: `${e.id}-${index}`,
              expectedValue: expVal,
              paidValue: paidVal,
              status: status
            };
          }),
          userName: ''
        };
      });

      localStorage.setItem('finance_app_version', APP_VERSION);
      return initialStore;
    } catch (e) {
      return {};
    }
  });

  const [insights, setInsights] = useState<string>("");
  const [loadingInsights, setLoadingInsights] = useState(false);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'list' | 'history'>('dashboard');

  useEffect(() => {
    if (isAuthenticated) {
      localStorage.setItem('finance_monthly_store', JSON.stringify(monthlyStore));
      setShowSaveIndicator(true);
      const timer = setTimeout(() => setShowSaveIndicator(false), 2000);
      return () => clearTimeout(timer);
    }
  }, [monthlyStore, isAuthenticated]);

  useEffect(() => {
    if (isAuthenticated) {
      localStorage.setItem('finance_categories', JSON.stringify(categories));
    }
  }, [categories, isAuthenticated]);

  // --- Funções de Autenticação ---
  const handleAuth = () => {
    const storedPwd = localStorage.getItem('finance_app_pwd');
    if (isSettingPassword) {
      if (passwordInput.length < 4) {
        setAuthError(true);
        return;
      }
      localStorage.setItem('finance_app_pwd', btoa(passwordInput));
      setIsAuthenticated(true);
      sessionStorage.setItem('finance_auth', 'true');
      setIsSettingPassword(false);
    } else {
      if (btoa(passwordInput) === storedPwd) {
        setIsAuthenticated(true);
        sessionStorage.setItem('finance_auth', 'true');
        setAuthError(false);
      } else {
        setAuthError(true);
        setPasswordInput('');
      }
    }
  };

  const handleLogout = () => {
    sessionStorage.removeItem('finance_auth');
    setIsAuthenticated(false);
    setPasswordInput('');
  };

  const currentMonthData = useMemo(() => monthlyStore[selectedMonth] || { expenses: [], userName: '' }, [monthlyStore, selectedMonth]);
  const expenses = currentMonthData.expenses;

  const filteredExpenses = useMemo(() => {
    if (!filterCategory) return expenses;
    return expenses.filter(e => e.category === filterCategory);
  }, [expenses, filterCategory]);

  const getMonthSummary = (monthIdx: number): SummaryData => {
    const data = monthlyStore[monthIdx];
    const monthExpenses = data ? data.expenses : [];
    const totalExpected = monthExpenses.reduce((acc, curr) => acc + (curr.expectedValue || 0), 0);
    const totalPaid = monthExpenses.reduce((acc, curr) => acc + (curr.paidValue || 0), 0);
    const fixedTotal = monthExpenses.filter(e => e.type === 'Fixa').reduce((acc, curr) => acc + (curr.paidValue || 0), 0);
    const variableTotal = monthExpenses.filter(e => e.type === 'Variável').reduce((acc, curr) => acc + (curr.paidValue || 0), 0);

    return {
      totalExpected,
      totalPaid,
      balance: totalExpected - totalPaid,
      progress: totalExpected > 0 ? (totalPaid / totalExpected) * 100 : 0,
      fixedTotal,
      variableTotal
    };
  };

  const currentSummary = useMemo(() => getMonthSummary(selectedMonth), [monthlyStore, selectedMonth]);

  const historyData = useMemo(() => {
    return MONTHS.map((name, index) => {
      const s = getMonthSummary(index);
      return {
        name: name.substring(0, 3),
        fullName: name,
        pago: s.totalPaid,
        previsto: s.totalExpected,
        index
      };
    });
  }, [monthlyStore]);

  const chartData = useMemo(() => {
    const cats = Array.from(new Set(expenses.map(e => e.category)));
    return cats.map((cat: string) => ({
      name: cat,
      value: expenses.filter(e => e.category === cat).reduce((acc, curr) => acc + (curr.paidValue || 0), 0),
      color: categories[cat]?.color || '#ccc'
    })).sort((a, b) => b.value - a.value);
  }, [expenses, categories]);

  const handleUpdateUserName = (name: string) => {
    setMonthlyStore(prev => ({
      ...prev,
      [selectedMonth]: { ...prev[selectedMonth], userName: name }
    }));
  };

  const handleUpdateExpense = (id: string, field: keyof Expense, value: any) => {
    setMonthlyStore(prev => {
      const newStore = { ...prev };
      const currentMonthData = prev[selectedMonth];
      if (!currentMonthData) return prev;

      const currentMonthExpenses = currentMonthData.expenses;
      const targetExpenseIndex = currentMonthExpenses.findIndex(e => e.id === id);

      if (targetExpenseIndex === -1) return prev;
      const currentExpense = currentMonthExpenses[targetExpenseIndex];

      if (field === 'description' || field === 'category') {
        const gid = currentExpense.groupId;
        for (let i = 0; i < 12; i++) {
          newStore[i] = {
            ...newStore[i],
            expenses: newStore[i].expenses.map(e => 
              e.groupId === gid ? { ...e, [field]: value } : e
            )
          };
        }
      } else {
        newStore[selectedMonth] = {
          ...newStore[selectedMonth],
          expenses: currentMonthExpenses.map(e => {
            if (e.id === id) {
              const updated = { ...e, [field]: value };
              const expVal = field === 'expectedValue' ? (parseFloat(value) || 0) : e.expectedValue;
              const paidVal = field === 'paidValue' ? (parseFloat(value) || 0) : e.paidValue;

              const status: ExpenseStatus = (expVal > 0 && paidVal === expVal) ? 'Pago' : 'Pendente';
              updated.status = status;

              return updated;
            }
            return e;
          })
        };
      }
      return newStore;
    });
  };

  const removeExpense = (id: string) => {
    const expenseToRemove = expenses.find(e => e.id === id);
    if (!expenseToRemove) return;

    if (confirm(`Remover "${expenseToRemove.description}" de TODOS os meses do ano?`)) {
      const gid = expenseToRemove.groupId;
      setMonthlyStore(prev => {
        const newStore = { ...prev };
        for (let i = 0; i < 12; i++) {
          newStore[i] = {
            ...newStore[i],
            expenses: newStore[i].expenses.filter(e => e.groupId !== gid)
          };
        }
        return newStore;
      });
    }
  };

  const toggleStatus = (id: string) => {
    setMonthlyStore(prev => {
      const monthData = prev[selectedMonth];
      if (!monthData) return prev;

      const newExpenses = monthData.expenses.map(e => {
        if (e.id === id) {
          const isMarkingPaid = e.status !== 'Pago';
          return { 
            ...e, 
            status: (isMarkingPaid ? 'Pago' : 'Pendente') as ExpenseStatus, 
            paidValue: isMarkingPaid ? (e.expectedValue > 0 ? e.expectedValue : 0) : 0 
          };
        }
        return e;
      });
      return { ...prev, [selectedMonth]: { ...monthData, expenses: newExpenses } };
    });
  };

  const addNewExpense = (catName?: string) => {
    const baseCategory = catName || Object.keys(categories)[0] || 'Geral';
    const baseDescription = catName || 'Novo Gasto';
    const baseGroupId = `group-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;

    setMonthlyStore(prev => {
      const newStore = { ...prev };
      for (let i = 0; i < 12; i++) {
        const monthData = newStore[i] || { expenses: [], userName: '' };
        const newExp: Expense = {
          id: `${baseGroupId}-${i}`,
          groupId: baseGroupId,
          description: baseDescription,
          category: baseCategory,
          type: 'Variável',
          expectedValue: 0,
          paidValue: 0,
          dueDate: '',
          status: 'Pendente' as ExpenseStatus
        };
        newStore[i] = {
          ...monthData,
          expenses: [...monthData.expenses, newExp]
        };
      }
      return newStore;
    });

    setActiveTab('list');
    setIsCategoryModalOpen(false);
  };

  const addCategory = () => {
    if (!newCatName.trim()) return;
    const catName = newCatName.trim();
    setCategories(prev => ({
      ...prev,
      [catName]: { name: catName, color: newCatColor }
    }));
    addNewExpense(catName);
    setNewCatName('');
  };

  const removeCategory = (name: string) => {
    if (confirm(`Remover a categoria "${name}"? Os gastos existentes não serão excluídos.`)) {
      const newCats = { ...categories };
      delete newCats[name];
      setCategories(newCats);
    }
  };

  const exportMonthToExcel = () => {
    const rows: any[] = [];
    const monthName = MONTHS[selectedMonth];
    const monthData = monthlyStore[selectedMonth];

    if (monthData && monthData.expenses.length > 0) {
      monthData.expenses.forEach(exp => {
        rows.push({
          'Mês': monthName,
          'Responsável': monthData.userName || '-',
          'Descrição': exp.description,
          'Categoria': exp.category,
          'Tipo': exp.type,
          'Valor Previsto (R$)': exp.expectedValue,
          'Valor Pago (R$)': exp.paidValue,
          'Dia Vencimento': exp.dueDate || '-',
          'Status': exp.status
        });
      });

      const worksheet = XLSX.utils.json_to_sheet(rows);
      const workbook = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(workbook, worksheet, `FinanceFlow_${monthName}`);

      const fileName = `FinanceFlow_${monthName}_${new Date().getFullYear()}.xlsx`;
      XLSX.writeFile(workbook, fileName);
    } else {
      alert("Não há lançamentos para exportar neste mês.");
    }
  };

  const exportFullBackupJSON = () => {
    const data = {
      monthlyStore,
      categories,
      exportDate: new Date().toISOString(),
      version: APP_VERSION
    };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `financeflow-full-backup.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const importData = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const content = e.target?.result as string;
        const imported = JSON.parse(content);
        if (imported.monthlyStore && imported.categories) {
          setMonthlyStore(imported.monthlyStore);
          setCategories(imported.categories);
          alert("Backup restaurado com sucesso!");
        }
      } catch (err) {
        alert("Erro ao importar backup.");
      }
    };
    reader.readAsText(file);
  };

  const fetchInsights = async () => {
    setLoadingInsights(true);
    const text = await getFinancialInsights(expenses);
    setInsights(text || "Nenhum insight disponível.");
    setLoadingInsights(false);
  };

  const formatBRL = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val || 0);

  // --- Tela de Login / Setup de Senha ---
  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center p-6">
        <div className="w-full max-w-md bg-slate-900 border border-slate-800 rounded-[2.5rem] p-8 md:p-12 shadow-2xl animate-in zoom-in duration-500">
          <div className="flex flex-col items-center gap-6 mb-10">
            <div className="p-4 bg-emerald-500 rounded-3xl shadow-xl shadow-emerald-500/20">
              {isSettingPassword ? <Lock className="w-8 h-8 text-slate-950" /> : <Unlock className="w-8 h-8 text-slate-950" />}
            </div>
            <div className="text-center">
              <h1 className="text-2xl font-black text-white mb-2">
                {isSettingPassword ? 'Definir Senha de Acesso' : 'Bem-vindo de volta'}
              </h1>
              <p className="text-slate-400 text-sm">
                {isSettingPassword ? 'Crie uma senha para proteger seus dados financeiros.' : 'Insira sua senha para acessar o FinanceFlow.'}
              </p>
            </div>
          </div>

          <div className="space-y-6">
            <div className="relative">
              <input 
                type="password"
                placeholder="Digite sua senha..."
                value={passwordInput}
                onChange={(e) => {
                  setPasswordInput(e.target.value);
                  setAuthError(false);
                }}
                onKeyDown={(e) => e.key === 'Enter' && handleAuth()}
                className={`w-full bg-slate-950 border ${authError ? 'border-red-500 animate-shake' : 'border-slate-800'} rounded-2xl px-6 py-4 text-center text-xl font-bold text-white placeholder:text-slate-700 focus:border-emerald-500 outline-none transition-all`}
                autoFocus
              />
              {authError && <p className="text-red-500 text-[10px] font-bold uppercase text-center mt-2 tracking-widest">Senha Incorreta</p>}
            </div>

            <button 
              onClick={handleAuth}
              className="w-full bg-emerald-500 hover:bg-emerald-400 text-slate-950 py-4 rounded-2xl font-black text-sm uppercase tracking-widest transition-all shadow-lg shadow-emerald-500/10 active:scale-95"
            >
