      <div className="p-3 bg-slate-800 rounded-2xl group-hover:scale-110 group-hover:bg-slate-700 transition-all">{icon}</div>
    </div>
    <div className="text-xl md:text-2xl font-bold mono text-white truncate">{value}</div>
  </div>
);

